_backend_version_cache = {"data": None, "ts": 0}
_backend_latest_cache = {"data": {}, "ts": 0}
_backend_model_cache = {"data": {}, "ts": {}}
_backend_runtime_cache = {"data": {}, "ts": {}, "fp": {}}
_bridge_benchmark_summary_cache = {"data": {}, "ts": 0.0}
_models_bootstrap_cache = {"data": None, "ts": 0.0, "fp": ""}
_models_snapshot_cache = {"data": None, "ts": 0.0, "fp": ""}
_cli_help_cache = {}
_cli_binary_fingerprints = {}


def _invalidate_backend_version_cache():
    _backend_version_cache["data"] = None
    _backend_version_cache["ts"] = 0


def _invalidate_models_payload_cache() -> None:
    _models_bootstrap_cache["data"] = None
    _models_bootstrap_cache["ts"] = 0.0
    _models_bootstrap_cache["fp"] = ""
    _models_snapshot_cache["data"] = None
    _models_snapshot_cache["ts"] = 0.0
    _models_snapshot_cache["fp"] = ""
    _backend_runtime_cache["data"].clear()
    _backend_runtime_cache["ts"].clear()
    _backend_runtime_cache["fp"].clear()


def _invalidate_bridge_benchmark_cache() -> None:
    _bridge_benchmark_summary_cache["data"] = {}
    _bridge_benchmark_summary_cache["ts"] = 0.0


def _cli_binary_fingerprint(binary: str) -> str:
    path = _resolve_cli(binary)
    if not path:
        return ""
    try:
        st = Path(path).stat()
        return f"{path}:{st.st_size}:{st.st_mtime_ns}"
    except Exception:
        return path


def _refresh_cli_cache_fingerprints(binaries=None) -> bool:
    binaries = tuple(binaries or ("openclaw", "claude", "gemini", "codex", "ollama"))
    changed = False
    for binary in binaries:
        fp = _cli_binary_fingerprint(binary)
        if _cli_binary_fingerprints.get(binary, "") != fp:
            _cli_binary_fingerprints[binary] = fp
            changed = True
    if changed:
        _invalidate_backend_version_cache()
        _invalidate_models_payload_cache()
        _cli_help_cache.clear()
        _backend_model_cache["data"].pop("gemini", None)
        _backend_model_cache["ts"].pop("gemini", None)
        global _capabilities_cache_ts
        _capabilities_cache_ts = 0.0
    return changed


def _cached_capability_version(name: str) -> dict:
    cap_key = {
        "gemini": "gemini_cli",
    }.get(name, name)
    cap = _capabilities_cache.get(cap_key) or {}
    if not isinstance(cap, dict):
        return {"version": "", "detected": False, "path": ""}
    ver = str(cap.get("version") or "").strip()
    if not cap.get("ok") or not ver:
        return {"version": "", "detected": False, "path": ""}
    m = re.search(r"\b\d{4}\.\d+\.\d+\b|\bv?\d+\.\d+\.\d+\b|\bv?\d+\.\d+\b", ver)
    parsed = m.group(0).lstrip("v") if m else ver.split()[-1].lstrip("v")
    return {"version": parsed or "", "detected": bool(parsed), "path": ""}


def _bootstrap_backend_versions() -> dict:
    versions = {}
    cached = _backend_version_cache.get("data") or {}
    latest_cache = dict(_backend_latest_cache.get("data") or {})
    for bk in ("openclaw", "ollama", "claude", "gemini", "codex"):
        base = dict(cached.get(bk) or {})
        if not base:
            if bk == "ollama":
                cap = _capabilities_cache.get("ollama") or {}
                ver = str(cap.get("version") or "").strip()
                sem = ""
                m = re.search(r"\b\d{4}\.\d+\.\d+\b|\bv?\d+\.\d+\.\d+\b|\bv?\d+\.\d+\b", ver)
                if m:
                    sem = m.group(0).lstrip("v")
                base = {"version": sem, "detected": bool(sem), "path": ""}
            else:
                base = _cached_capability_version(bk)
        if bk in latest_cache and isinstance(latest_cache[bk], dict):
            base.update({k: v for k, v in latest_cache[bk].items() if v})
        versions[bk] = base
    return versions


