def _cli_help_text(binary: str, args=None) -> str:
    args = tuple(args or [])
    key = (binary,) + args
    cached = _cli_help_cache.get(key)
    if cached and (time.time() - cached[0]) < 3600:
        return cached[1]
    path = _resolve_cli(binary)
    if not path:
        return ""
    try:
        result = subprocess.run([path, *args, "--help"], capture_output=True, text=True, timeout=8, env=_agent_env(), cwd=str(Path.home()))
        text = ((result.stdout or "") + "\n" + (result.stderr or "")).strip()
    except Exception:
        text = ""
    _cli_help_cache[key] = (time.time(), text)
    return text


def _gemini_auth_mode() -> str:
    if os.environ.get("GEMINI_API_KEY") or os.environ.get("GOOGLE_API_KEY"):
        return "api_key"
    gdir = Path.home() / ".gemini"
    if (gdir / "oauth_creds.json").exists():
        return "oauth"
    return "unknown"


def _normalize_gemini_model_id(model_id: str, auth_mode: str = "") -> str:
    text = _clean_runtime_model_id(model_id)
    if not text:
        return ""
    low = text.lower()
    if auth_mode == "oauth":
        if "flash-lite" in low:
            return "gemini-2.5-flash-lite"
        if "flash" in low:
            return "gemini-2.5-flash"
        if "pro" in low:
            return "gemini-2.5-pro"
    return text


def _backend_runtime_info(backend: str) -> dict:
    backend = str(backend or "").strip().lower()
    now = time.time()
    fp = _cli_binary_fingerprint(backend)
    if backend == "gemini":
        fp = f"{fp}|{_gemini_auth_mode()}"
    cached = _backend_runtime_cache["data"].get(backend)
    cache_ts = float(_backend_runtime_cache["ts"].get(backend) or 0.0)
    cache_fp = _backend_runtime_cache["fp"].get(backend, "")
    if cached and cache_fp == fp and (now - cache_ts) < 60:
        return dict(cached)
    spec = dict(BACKEND_RUNTIME_SPECS.get(backend) or {})
    info = {"backend": backend, "spec": spec}
    if backend == "gemini":
        help_text = _cli_help_text("gemini")
        auth_mode = _gemini_auth_mode()
        info.update({
            "auth_mode": auth_mode,
            "supports_json_output": "--output-format" in help_text and "json" in help_text.lower(),
            "supports_model_flag": "-m, --model" in help_text or "--model" in help_text,
            "supports_headless": "-p, --prompt" in help_text or "--prompt" in help_text,
            "recommended_smoke_model": "gemini-2.5-flash" if auth_mode in ("oauth", "unknown") else "",
        })
    elif backend == "claude":
        help_text = _cli_help_text("claude")
        info.update({
            "supports_json_output": "--output-format" in help_text and "json" in help_text.lower(),
            "supports_model_flag": "--model" in help_text,
            "supports_headless": "-p, --print" in help_text or "--print" in help_text,
        })
    elif backend == "codex":
        help_text = _cli_help_text("codex", ("exec",))
        info.update({
            "supports_json_output": "--json" in help_text,
            "supports_model_flag": "--model" in help_text,
            "supports_headless": True,
        })
    elif backend == "openclaw":
        help_text = _cli_help_text("openclaw", ("agent",))
        info.update({
            "supports_json_output": "--json" in help_text,
            "supports_model_flag": False,
            "supports_headless": True,
        })
    elif backend == "ollama":
        info.update({
            "supports_json_output": True,
            "supports_model_flag": True,
            "supports_headless": True,
        })
    info.update(_bridge_runtime_semantics(backend))
    info["chips"] = _runtime_chip_definitions(backend, info, {})
    _backend_runtime_cache["data"][backend] = dict(info)
    _backend_runtime_cache["ts"][backend] = now
    _backend_runtime_cache["fp"][backend] = fp
    return info


def _probe_backend_versions(force: bool = False):
    """Detect installed/current versions quickly and refresh latest checks on a slower cadence."""
    import time as _t
    now = _t.time()
    if force:
        _invalidate_backend_version_cache()
    if _backend_version_cache["data"] and (now - _backend_version_cache["ts"]) < 30:
        return _backend_version_cache["data"]

    versions = {}

    def _extract_semverish(text):
        text = str(text or "").strip()
        if not text:
            return ""
        m = re.search(r"\b\d{4}\.\d+\.\d+\b", text)
        if m:
            return m.group(0)
        m = re.search(r"\bv?\d+\.\d+\.\d+\b", text)
        if m:
            return m.group(0).lstrip("v")
        m = re.search(r"\bv?\d+\.\d+\b", text)
        if m:
            return m.group(0).lstrip("v")
        return ""

    def _resolve_bin(name):
        """Prefer user-local installs over system PATH to avoid stale distro shims."""
        for d in (str(Path.home() / ".npm-global" / "bin"), str(Path.home() / ".local" / "bin"), "/usr/local/bin", "/usr/bin", "/bin"):
            c = Path(d) / name
            if c.exists():
                return str(c)
        p = shutil.which(name)
        if p:
            return p
        return None

    def _cli_version(name, parse_fn=None):
        """Run binary --version, return version string or empty."""
        path = _resolve_bin(name)
        if not path:
            return {"version": "", "detected": False, "path": ""}
        try:
            _env = dict(os.environ)
            _home = str(Path.home())
            _extra = f"{_home}/.npm-global/bin:{_home}/.local/bin:/usr/local/bin"
            _env["PATH"] = _extra + ":" + _env.get("PATH", "")
            _env["HOME"] = _home
            result = subprocess.run([path, "--version"], capture_output=True, text=True, timeout=5, env=_env)
            out = (result.stdout or result.stderr or "").strip()
            ver = parse_fn(out) if parse_fn else out.split()[-1] if out else ""
            return {"version": ver, "detected": True, "path": path} if ver else {"version": "", "detected": False, "path": path}
        except Exception:
            return {"version": "", "detected": False, "path": path}

    def _npm_latest(pkg_name):
        try:
            result = subprocess.run(["npm", "view", pkg_name, "version"], capture_output=True, text=True, timeout=3, env=_agent_env())
            latest = (result.stdout or "").strip().splitlines()
            latest = latest[-1].strip() if latest else ""
            return _extract_semverish(latest)
        except Exception:
            return ""

    def _http_json(url, timeout=3):
        try:
            import urllib.request
            with urllib.request.urlopen(url, timeout=timeout) as resp:
                return json.loads(resp.read().decode("utf-8"))
        except Exception:
            return None

    def _github_latest_release(repo):
        data = _http_json(f"https://api.github.com/repos/{repo}/releases/latest", timeout=4)
        if not isinstance(data, dict):
            return ""
        return _extract_semverish(data.get("tag_name", ""))

    # OpenClaw
    versions["openclaw"] = _cached_capability_version("openclaw")
    if not versions["openclaw"].get("detected"):
        versions["openclaw"] = _cli_version("openclaw", _extract_semverish)

    # Ollama
    versions["ollama"] = _cli_version("ollama", _extract_semverish)
    try:
        import urllib.request, json as _j2
        req = urllib.request.Request("http://127.0.0.1:11434/api/version", method="GET")
        with urllib.request.urlopen(req, timeout=3) as resp:
            data = _j2.loads(resp.read())
            api_ver = _extract_semverish(data.get("version", ""))
            if api_ver:
                versions["ollama"]["version"] = api_ver
                versions["ollama"]["detected"] = True
    except Exception:
        pass

    # Claude CLI — prefer cached capability result to avoid redundant process spawn on tab load
    versions["claude"] = _cached_capability_version("claude")
    if not versions["claude"].get("detected"):
        versions["claude"] = _cli_version("claude", _extract_semverish)

    # Gemini — CLI startup is relatively slow, so reuse capability cache when available
    versions["gemini"] = _cached_capability_version("gemini")
    if not versions["gemini"].get("detected"):
        versions["gemini"] = _cli_version("gemini", _extract_semverish)

    # Codex — also check ~/.codex/version.json for latest available
    _cdx_ver = _cached_capability_version("codex")
    if not _cdx_ver.get("detected"):
        _cdx_ver = _cli_version("codex", _extract_semverish)
    try:
        _cdx_vjson = json.loads((Path.home() / ".codex" / "version.json").read_text())
        _cdx_latest = _cdx_vjson.get("latest_version", "")
        if _cdx_latest:
            _cdx_ver["latest"] = _extract_semverish(_cdx_latest) or str(_cdx_latest)
            _cdx_ver["update_cmd"] = "npm i -g @openai/codex"
    except Exception:
        pass
    versions["codex"] = _cdx_ver

    # Google Workspace CLI
    versions["gws"] = _cli_version("gws")

    latest_cache = dict(_backend_latest_cache.get("data") or {})
    latest_stale = force or ((now - float(_backend_latest_cache.get("ts") or 0)) >= 21600)
    if latest_stale:
        refreshed = {}
        try:
            oc_update = json.loads((OPENCLAW_STATE_DIR / "update-check.json").read_text(encoding="utf-8"))
            oc_latest = _extract_semverish(oc_update.get("lastNotifiedVersion", ""))
            if oc_latest:
                refreshed["openclaw"] = {"latest": oc_latest, "update_cmd": "npm uninstall -g openclaw && npm i -g openclaw"}
        except Exception:
            pass
        if not refreshed.get("openclaw"):
            _oc_latest = _npm_latest("openclaw")
            if _oc_latest:
                refreshed["openclaw"] = {"latest": _oc_latest, "update_cmd": "npm uninstall -g openclaw && npm i -g openclaw"}
        _cl_latest = _npm_latest("@anthropic-ai/claude-code")
        if _cl_latest:
            refreshed["claude"] = {"latest": _cl_latest, "update_cmd": "npm i -g @anthropic-ai/claude-code"}
        _gm_latest = _npm_latest("@google/gemini-cli")
        if _gm_latest:
            refreshed["gemini"] = {"latest": _gm_latest, "update_cmd": "npm i -g @google/gemini-cli"}
        _cdx_latest = _npm_latest("@openai/codex")
        if _cdx_latest:
            refreshed["codex"] = {"latest": _cdx_latest, "update_cmd": "npm i -g @openai/codex"}
        _ollama_latest = _github_latest_release("ollama/ollama")
        if _ollama_latest:
            refreshed["ollama"] = {"latest": _ollama_latest, "update_cmd": "curl -fsSL https://ollama.com/install.sh | sh"}
        latest_cache = refreshed
        _backend_latest_cache["data"] = latest_cache
        _backend_latest_cache["ts"] = now

    for _bk, _latest in latest_cache.items():
        if _bk in versions and isinstance(_latest, dict):
            versions[_bk].update({k: v for k, v in _latest.items() if v})

    _backend_version_cache["data"] = versions
    _backend_version_cache["ts"] = now
    return versions


def _model_display_name(model_id: str) -> str:
    """Prefer runtime IDs over stale marketing labels; lightly normalize when obvious."""
    text = str(model_id or "").strip()
    if not text:
        return ""
    slug = text.split("/")[-1]
    pretty = slug.replace("_", "-")
    if pretty.startswith("gpt-"):
        return pretty.upper()
    if pretty.startswith("claude-"):
        return "Claude " + pretty[len("claude-"):].replace("-", " ").title()
    if pretty.startswith("gemini-"):
        return "Gemini " + pretty[len("gemini-"):].replace("-", " ").title()
    return pretty


def _bridge_runtime_semantics(backend: str, model_id: str = "") -> dict:
    backend = str(backend or "").strip().lower()
    model_id = str(model_id or "").strip()
    if backend == "openclaw":
        control_mode = "agent-default"
        notes = ["OpenClaw currently treats Porter model selection as advisory."]
        if model_id and model_id not in ("auto", "main"):
            notes.append("Exact model switching is not available on this OpenClaw path yet.")
        return {
            "control_mode": control_mode,
            "supports_exact_model": False,
            "honors_model_selection": False,
            "bridge_target": "main",
            "notes": notes,
        }
    if backend == "gemini":
        auth_mode = _gemini_auth_mode()
        exact = auth_mode == "api_key"
        return {
            "control_mode": "exact" if exact else "alias",
            "supports_exact_model": exact,
            "honors_model_selection": True,
            "bridge_target": model_id,
            "notes": ["OAuth mode may remap Gemini aliases at runtime."] if auth_mode == "oauth" else [],
        }
    return {
        "control_mode": "exact",
        "supports_exact_model": True,
        "honors_model_selection": True,
        "bridge_target": model_id,
        "notes": [],
    }


def _runtime_chip_definitions(backend: str, runtime: dict | None = None, available: dict | None = None) -> list[dict]:
    backend = str(backend or "").strip().lower()
    runtime = runtime or {}
    available = available or {}
    chips = []
    if backend == "openclaw":
        chips.append({
            "label": "Gateway Bridge",
            "tooltip": "Porter reaches OpenClaw through its gateway runtime instead of talking directly to a model API.",
        })
        if runtime.get("honors_model_selection") is False:
            chips.append({
                "label": "Advisory Selection",
                "tooltip": "OpenClaw treats Porter model selection as advisory on this path instead of switching to an exact model target.",
            })
    elif backend == "gemini":
        auth_mode = str(runtime.get("auth_mode") or "unknown").strip().lower()
        chips.append({
            "label": "CLI Runtime",
            "tooltip": "Porter uses the Gemini runtime available in this environment and its current auth/session state.",
        })
        chips.append({
            "label": "Exact Selection" if runtime.get("control_mode") == "exact" else "Alias Selection",
            "tooltip": "Exact selection means Porter can ask for a specific model ID directly. Alias selection means the Gemini CLI may remap the requested model at runtime.",
        })
        if auth_mode == "oauth":
            chips.append({
                "label": "OAuth Profile",
                "tooltip": "This Gemini runtime is using OAuth mode, so model aliases and auth prompts are managed by that environment session.",
            })
    elif backend == "claude":
        chips.append({
            "label": "CLI Runtime",
            "tooltip": "Porter uses the Claude runtime available in this environment and its current auth/session state.",
        })
        if runtime.get("supports_json_output"):
            chips.append({
                "label": "Structured Output",
                "tooltip": "Porter can ask the Claude CLI for structured output during tests and bridge dispatch bookkeeping.",
            })
    elif backend == "codex":
        chips.append({
            "label": "CLI Runtime",
            "tooltip": "Porter uses the Codex runtime available in this environment and its current auth/session state.",
        })
        chips.append({
            "label": "Structured Output",
            "tooltip": "Porter uses Codex JSON/JSONL event output so bridge telemetry and parsing stay reliable.",
        })
    elif backend == "ollama":
        chips.append({
            "label": "HTTP Runtime",
            "tooltip": "Porter talks to the Ollama runtime over HTTP at the configured host and port for this environment.",
        })
    if available.get("resolved") and runtime.get("honors_model_selection") is False:
        chips.append({
            "label": "Model Preference",
            "tooltip": "The model picker still matters for operator intent and diagnostics, but this backend cannot honor it as an exact runtime switch yet.",
        })
    return chips


def _clean_runtime_model_id(model_id: str) -> str:
    model_id = str(model_id or "").strip()
    if not model_id:
        return ""
    low = model_id.lower()
    if low.startswith("<") and low.endswith(">"):
        return ""
    if low in {"synthetic", "<synthetic>", "auto"}:
        return ""
    return model_id


def _canonical_model_key(model_id: str) -> str:
    model_id = _clean_runtime_model_id(model_id)
    if not model_id:
        return ""
    return model_id.split("/")[-1].strip().lower()


def _unique_model_catalog(entries, preferred_id=""):
    """Dedupe model entries while preserving order and honoring a preferred active ID."""
    preferred_id = str(preferred_id or "").strip()
    seen = set()
    ordered = []
    pending = []
    for entry in entries or []:
        if not isinstance(entry, dict):
            continue
        model_id = _clean_runtime_model_id(entry.get("id", ""))
        canonical = _canonical_model_key(model_id)
        if not model_id or canonical in seen:
            continue
        seen.add(canonical)
        item = {
            "id": model_id,
            "name": str(entry.get("name") or _model_display_name(model_id) or model_id),
            "default": False,
        }
        if model_id == preferred_id:
            ordered.insert(0, item)
        else:
            pending.append(item)
    ordered.extend(pending)
    if ordered:
        ordered[0]["default"] = True
    return ordered


def _preferred_runtime_model_id(backend: str, models: list, active_choice: str = "") -> str:
    active_choice = _clean_runtime_model_id(active_choice)
    ids = [str(m.get("id", "")).strip() for m in (models or []) if isinstance(m, dict)]
    if active_choice and active_choice in ids:
        return active_choice
    if backend == "gemini":
        for needle in ("gemini-2.5-flash", "gemini-2.5-pro", "flash", "pro"):
            for model_id in ids:
                low = model_id.lower()
                if needle in low and "preview" not in low:
                    return model_id
        for model_id in ids:
            low = model_id.lower()
            if "preview" not in low:
                return model_id
    return ""


def _discover_openclaw_models(active_choice=""):
    oc_bin = _resolve_cli("openclaw")
    if not oc_bin:
        return []
    try:
        result = subprocess.run([oc_bin, "models", "list", "--json"], capture_output=True, text=True, timeout=15, env=_agent_env(), cwd=str(Path.home()))
        raw = ((result.stdout or "").strip() or (result.stderr or "").strip())
        if result.returncode == 0 and raw:
            payload = json.loads(raw[raw.find("{"):]) if "{" in raw else {}
            models = []
            for item in payload.get("models", []):
                if not isinstance(item, dict):
                    continue
                model_id = _clean_runtime_model_id(item.get("key") or item.get("id") or "")
                if not model_id or item.get("missing"):
                    continue
                models.append({
                    "id": model_id,
                    "name": str(item.get("name") or _model_display_name(model_id) or model_id),
                    "default": "default" in (item.get("tags") or []) or "configured" in (item.get("tags") or []),
                })
            if models:
                preferred = next((m["id"] for m in models if m.get("default")), "") or active_choice
                return _unique_model_catalog(models, preferred)
    except Exception as e:
        log.debug("OpenClaw model discovery failed: %s", e)
    return []


def _discover_models_from_claude_history(active_choice=""):
    claude_dir = Path.home() / ".claude" / "projects"
    if not claude_dir.exists():
        return []
    observed = {}
    for jsonl_file in sorted(claude_dir.rglob("*.jsonl"), key=lambda p: p.stat().st_mtime, reverse=True)[:80]:
        try:
            with open(jsonl_file, "r", encoding="utf-8") as fh:
                for idx, line in enumerate(fh):
                    if idx >= 400:
                        break
                    try:
                        entry = json.loads(line)
                    except Exception:
                        continue
                    model_id = ""
                    msg = entry.get("message", {})
                    if isinstance(msg, dict):
                        model_id = _clean_runtime_model_id(msg.get("model") or "")
                    if not model_id:
                        model_id = _clean_runtime_model_id(entry.get("model") or "")
                    if model_id:
                        observed.setdefault(model_id, {"id": model_id, "name": _model_display_name(model_id) or model_id})
        except Exception as e:
            log.debug("Claude model scan skip %s: %s", jsonl_file, e)
    return _unique_model_catalog(list(observed.values()), active_choice)


def _discover_models_from_gemini_history(active_choice=""):
    gemini_root = Path.home() / ".gemini" / "tmp"
    if not gemini_root.exists():
        return []
    runtime = _backend_runtime_info("gemini")
    auth_mode = runtime.get("auth_mode", "")
    observed = {}
    for json_file in sorted(gemini_root.rglob("chats/*.json"), key=lambda p: p.stat().st_mtime, reverse=True)[:80]:
        try:
            data = json.loads(json_file.read_text(encoding="utf-8"))
        except Exception:
            continue
        stack = [data]
        while stack:
            cur = stack.pop()
            if isinstance(cur, dict):
                for k, v in cur.items():
                    if k == "model" and isinstance(v, str) and v.strip():
                        model_id = _normalize_gemini_model_id(v, auth_mode)
                        observed.setdefault(model_id, {"id": model_id, "name": _model_display_name(model_id) or model_id})
                    elif isinstance(v, (dict, list)):
                        stack.append(v)
            elif isinstance(cur, list):
                stack.extend(cur)
    if auth_mode == "oauth":
        for stable in ("gemini-2.5-flash", "gemini-2.5-pro"):
            observed.setdefault(stable, {"id": stable, "name": _model_display_name(stable) or stable})
    return _unique_model_catalog(list(observed.values()), active_choice)


def _legacy_config_models(backend):
    bc = _config.get("backend_config", {}).get(backend, {})
    models = bc.get("models", [])
    cleaned = []
    for m in models:
        if not isinstance(m, dict):
            continue
        model_id = _clean_runtime_model_id(m.get("id", ""))
        if not model_id:
            continue
        item = dict(m)
        item["id"] = model_id
        cleaned.append(item)
    return cleaned


def _get_available_models(backend):
    """Return models for a backend. Runtime discovery is authoritative; config is fallback only."""
    prefs = _config.get("preferences", {})
    active_models = prefs.get("active_models", {})
    active_choice = str(active_models.get(backend, "")).strip()
    now = time.time()
    cached = _backend_model_cache["data"].get(backend)
    cache_ts = float(_backend_model_cache["ts"].get(backend) or 0)
    if cached is not None and (now - cache_ts) < 90:
        return cached

    if backend == "codex":
        # Read from Codex CLI models cache (auto-updated by codex)
        try:
            cache_path = Path.home() / ".codex" / "models_cache.json"
            if cache_path.exists():
                data = json.loads(cache_path.read_text(encoding="utf-8"))
                models = []
                for m in sorted(data.get("models", []), key=lambda x: x.get("priority", 99)):
                    if m.get("visibility") == "hide":
                        continue
                    slug = m.get("slug", "")
                    if slug:
                        models.append({"id": slug, "name": m.get("display_name", slug), "default": len(models) == 0})
                if models:
                    _backend_model_cache["data"][backend] = models
                    _backend_model_cache["ts"][backend] = now
                    return models
        except Exception:
            pass
        models = _unique_model_catalog(_legacy_config_models("codex"), active_choice)
        _backend_model_cache["data"][backend] = models
        _backend_model_cache["ts"][backend] = now
        return models
    if backend == "ollama":
        try:
            import urllib.request, json as _j
            bc = _config.get("backend_config", {}).get("ollama", {})
            _oll_host = bc.get("host", "127.0.0.1")
            _oll_port = bc.get("port", 11434)
            req = urllib.request.Request(f"http://{_oll_host}:{_oll_port}/api/tags", method="GET")
            with urllib.request.urlopen(req, timeout=3) as resp:
                data = _j.loads(resp.read())
                models = []
                for m in data.get("models", []):
                    name = m.get("name", "")
                    if name:
                        models.append({"id": name, "name": name, "default": len(models) == 0})
                _backend_model_cache["data"][backend] = models
                _backend_model_cache["ts"][backend] = now
                return models
        except Exception:
            models = _unique_model_catalog(_legacy_config_models("ollama"), active_choice)
            _backend_model_cache["data"][backend] = models
            _backend_model_cache["ts"][backend] = now
            return models
    if backend == "openclaw":
        models = _discover_openclaw_models(active_choice)
    elif backend == "claude":
        models = _discover_models_from_claude_history(active_choice)
    elif backend == "gemini":
        models = _discover_models_from_gemini_history(active_choice)
    else:
        models = []

    fallback = _legacy_config_models(backend)
    if active_choice and not any(m.get("id") == active_choice for m in models):
        fallback = ([{"id": active_choice, "name": _model_display_name(active_choice) or active_choice}] + fallback)
    models = _unique_model_catalog(models + fallback, active_choice)
    _backend_model_cache["data"][backend] = models
    _backend_model_cache["ts"][backend] = now
    return models


def _get_active_model(backend):
    """Return the active model ID for a backend. Resolves 'auto' to default."""
    prefs = _config.get("preferences", {})
    active_models = prefs.get("active_models", {})
    choice = active_models.get(backend, "auto")
    if choice == "auto":
        models = _get_available_models(backend)
        for m in models:
            if m.get("default"):
                return m["id"]
        return models[0]["id"] if models else ""
    return choice


def _record_bridge_benchmark(benchmark_kind: str, backend: str, requested_model: str = "",
                             resolved_model: str = "", ok: bool = False, latency_ms: int = 0,
                             error: str = "", metadata: dict | None = None) -> None:
    try:
        conn = _db_conn()
        conn.execute(
            """INSERT INTO bridge_benchmarks
               (benchmark_kind, backend, requested_model, resolved_model, ok, latency_ms, error, metadata, created_at)
               VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)""",
            (
                str(benchmark_kind or "dispatch")[:40],
                str(backend or "")[:40],
                str(requested_model or "")[:160],
                str(resolved_model or "")[:160],
                1 if ok else 0,
                max(0, int(latency_ms or 0)),
                str(error or "")[:500],
                json.dumps(metadata or {}, ensure_ascii=True),
                time.time(),
            ),
        )
        conn.commit()
        conn.close()
        _invalidate_bridge_benchmark_cache()
    except Exception as e:
        log.debug("Bridge benchmark record failed: %s", e)


def _bridge_benchmark_summary(window_s: int = 86400) -> dict:
    now = time.time()
    cache_key = str(int(window_s or 86400))
    cached = (_bridge_benchmark_summary_cache.get("data") or {}).get(cache_key)
    if cached and (now - float(_bridge_benchmark_summary_cache.get("ts") or 0.0)) < 30.0:
        return dict(cached)
    out = {}
    try:
        conn = _db_conn()
        since = now - max(300, int(window_s or 86400))
        for backend in PROVIDER_REGISTRY:
            rows = conn.execute(
                """SELECT benchmark_kind, requested_model, resolved_model, ok, latency_ms, created_at
                   FROM bridge_benchmarks
                   WHERE backend=? AND created_at>=?
                   ORDER BY created_at DESC LIMIT 200""",
                (backend, since),
            ).fetchall()
            latencies = [int(r["latency_ms"] or 0) for r in rows if int(r["latency_ms"] or 0) > 0]
            test_rows = [r for r in rows if str(r["benchmark_kind"] or "") == "connectivity"]
            success_count = sum(1 for r in rows if int(r["ok"] or 0))
            sample_count = len(rows)
            success_rate = int(round((success_count / sample_count) * 100)) if sample_count else 0
            p50 = 0
            p95 = 0
            if latencies:
                ordered = sorted(latencies)
                p50 = ordered[max(0, min(len(ordered) - 1, len(ordered) // 2))]
                p95 = ordered[max(0, min(len(ordered) - 1, math.ceil(len(ordered) * 0.95) - 1))]
            latest = dict(rows[0]) if rows else {}
            out[backend] = {
                "samples": sample_count,
                "success_rate": success_rate,
                "p50_ms": p50,
                "p95_ms": p95,
                "test_samples": len(test_rows),
                "latest_kind": str(latest.get("benchmark_kind") or ""),
                "latest_requested_model": str(latest.get("requested_model") or ""),
                "latest_resolved_model": str(latest.get("resolved_model") or ""),
                "latest_ok": bool(latest.get("ok")) if latest else False,
                "latest_at": float(latest.get("created_at") or 0),
            }
        conn.close()
    except Exception as e:
        log.debug("Bridge benchmark summary failed: %s", e)
    _bridge_benchmark_summary_cache.setdefault("data", {})[cache_key] = dict(out)
    _bridge_benchmark_summary_cache["ts"] = now
    return out


def _benchmark_adjusted_route(preferred: str, message: str = "") -> tuple:
    preferred = str(preferred or "").strip().lower()
    if not preferred:
        return (preferred, None)
    summary = _bridge_benchmark_summary(86400)
    pref_stats = summary.get(preferred) or {}
    pref_pressure = _bridge_scheduler_backend_pressure(preferred)
    if int(pref_stats.get("samples") or 0) < 3:
        if pref_pressure.get("saturated") and pref_pressure.get("waiting", 0) > 0:
            return _resolve_with_fallback(preferred, message)
        return (preferred, None) if _probe_provider(preferred) and not _backend_is_circuit_open(preferred) else _resolve_with_fallback(preferred, message)
    pref_success = int(pref_stats.get("success_rate") or 0)
    pref_p50 = int(pref_stats.get("p50_ms") or 0)
    # v0.31.44 — Fast path: if preferred is healthy and not saturated, skip alternatives
    if _probe_provider(preferred) and not _backend_is_circuit_open(preferred) and not pref_pressure.get("saturated"):
        return (preferred, None)
    prefs = _config.get("preferences", {})
    chain = prefs.get("fallback_chain", _DEFAULT_FALLBACK_CHAIN)
    best = preferred
    best_score = None
    for backend in [preferred] + [bk for bk in chain if bk != preferred]:
        if not backend:
            continue
        if not _probe_provider(backend) or _backend_is_circuit_open(backend):
            continue
        stats = summary.get(backend) or {}
        pressure = _bridge_scheduler_backend_pressure(backend)
        samples = int(stats.get("samples") or 0)
        success_rate = int(stats.get("success_rate") or 0)
        p50 = int(stats.get("p50_ms") or 0)
        if backend != preferred and samples < 3:
            continue
        if backend != preferred and success_rate + 5 < pref_success:
            continue
        # Lower score is better. Preserve preferred unless the alternative is materially faster.
        effective_p50 = p50 or 999999
        effective_p50 += int(pressure.get("avg_wait_ms", 0) or 0)
        effective_p50 += int(pressure.get("waiting", 0) or 0) * 300
        if pressure.get("saturated"):
            effective_p50 += 1000
        score = effective_p50 - (success_rate * 20)
        if backend == preferred:
            best_score = score
            continue
        faster_enough = pref_p50 and effective_p50 and effective_p50 <= int(pref_p50 * 0.75)
        if best_score is not None and faster_enough and score < best_score:
            best = backend
            best_score = score
    if best != preferred:
        mlog.emit("info", "routing", "route.benchmark_override",
                  f"Benchmark override: {preferred} → {best}",
                  preferred=preferred, override=best,
                  extra={"preferred": pref_stats, "chosen": summary.get(best) or {}})
        return (best, None)
    return _resolve_with_fallback(preferred, message)


def _openclaw_gateway_settings() -> dict:
    """Load OpenClaw gateway port/token. Config priority: Porter config > discovered runtime config."""
    bc = _config.get("backend_config", {}).get("openclaw", {})
    port = int(bc.get("gateway_port", 0) or bc.get("port", 0) or 0) or 18789
    host = str(bc.get("host", "")).strip() or "127.0.0.1"
    token = str(bc.get("auth_token", "")).strip()
    source = "Porter config override" if any(str(bc.get(k, "")).strip() for k in ("auth_token", "host")) or int(bc.get("gateway_port", 0) or bc.get("port", 0) or 0) else "Discovered runtime config"
    # Fall back to the discovered runtime config if no token is stored in Porter config.
    if not token or source == "Discovered runtime config":
        try:
            oc_cfg = json.loads((OPENCLAW_STATE_DIR / "openclaw.json").read_text(encoding="utf-8"))
            gw = oc_cfg.get("gateway", {}) if isinstance(oc_cfg, dict) else {}
            if not int(bc.get("gateway_port", 0) or bc.get("port", 0) or 0):
                port = int(gw.get("port") or oc_cfg.get("gatewayPort") or 18789)
            if not str(bc.get("host", "")).strip():
                bind = str(gw.get("bind") or oc_cfg.get("gatewayBind") or "").strip().lower()
                host = "127.0.0.1" if bind in ("", "loopback", "127.0.0.1", "localhost") else (bind or host)
            auth = gw.get("auth", {}) if isinstance(gw, dict) else {}
            if not token:
                token = str(auth.get("token") or gw.get("token") or oc_cfg.get("authToken") or "").strip()
        except Exception as e:
            log.debug("OpenClaw gateway config read failed: %s", e)
    return {"host": host, "port": port, "token": token, "source": source}


def _model_repair_hint(backend: str, detail: str = "") -> dict:
    """Return operator-facing repair hints for known backend failure modes."""
    backend = str(backend or "").strip().lower()
    text = str(detail or "").lower()
    hint = {}
    if backend == "openclaw":
        if any(tok in text for tok in ("cannot find module", "module not found", "err_module_not_found", "syntaxerror", "typeerror", "node:internal")):
            hint["repair_hint"] = "OpenClaw CLI install appears broken. Reinstall the CLI, then re-open/auth the gateway."
            hint["reinstall_cmd"] = "npm uninstall -g openclaw && npm i -g openclaw"
        elif "duplicate_service_units" in text or "competing service units" in text or "supervisor conflict" in text:
            hint["repair_hint"] = "OpenClaw has competing service units or supervisors. Reinstall will not fix that; disable the duplicate unit so only one gateway service owns the port."
            hint["repair_cmd"] = "systemctl status openclaw-gateway"
            hint["followup_hint"] = "Check both /etc/systemd/system/openclaw-gateway.service and ~/.config/systemd/user/openclaw-gateway.service."
        elif "service_restart_loop" in text or "service restart" in text or "restarting itself every few seconds" in text:
            hint["repair_hint"] = "OpenClaw gateway is entering a service restart loop. This is runtime breakage in OpenClaw, not just a bad model test."
            hint["repair_cmd"] = "openclaw status"
            hint["followup_hint"] = "Review the OpenClaw gateway service/logs before changing Porter config."
        elif "paired devices exist" in text or "connected and reconnected" in text or "reconnect loop" in text:
            hint["repair_hint"] = "OpenClaw looks paired but unstable. If it loops between connected and reconnected, stop the gateway and reset devices/paired.json plus devices/pending.json, then pair again."
            hint["repair_cmd"] = "openclaw gateway stop"
            hint["followup_hint"] = "Then back up or clear ~/.openclaw/devices/paired.json and ~/.openclaw/devices/pending.json before re-pairing."
        elif "agent_path_flaky" in text or "agent runs are intermittent" in text:
            hint["repair_hint"] = "OpenClaw gateway is up, but real agent runs are intermittent. Recheck the active gateway service, then test one direct agent run before blaming Porter."
            hint["repair_cmd"] = "openclaw agent --agent main --message \"Reply with just the word OK\" --json --timeout 45"
            hint["followup_hint"] = "If this flaps between success and 1006/timeout, inspect the active openclaw-gateway service and its journal."
        elif "gateway not running" in text:
            hint["repair_hint"] = "OpenClaw gateway is down. Run doctor --fix or stop/reset pairing state if the UI keeps reconnecting."
            hint["repair_cmd"] = "openclaw doctor --fix"
        elif "auth" in text or "token" in text or "unauthorized" in text:
            hint["repair_hint"] = "OpenClaw auth looks invalid. Refresh the auth token or reconnect the gateway profile."
        elif "timed out" in text or "timeout" in text:
            hint["repair_hint"] = "OpenClaw did not answer in time. Check whether the gateway is crash-looping or blocked on startup."
        else:
            if text.strip():
                hint["repair_hint"] = "Check OpenClaw bridge health, agent execution, and auth before changing the install."

    elif backend == "claude":
        hint["reinstall_cmd"] = "npm i -g @anthropic-ai/claude-code"
        if "auth" in text or "login" in text or "token" in text:
            hint["repair_hint"] = "Claude Code needs authentication or token refresh before model tests can succeed."
    elif backend == "gemini":
        hint["reinstall_cmd"] = "npm i -g @google/gemini-cli"
        if "auth" in text or "oauth" in text or "authorize" in text or "login" in text:
            hint["repair_hint"] = "Gemini CLI needs authentication before model tests can succeed."
    elif backend == "codex":
        hint["reinstall_cmd"] = "npm i -g @openai/codex"
        if "auth" in text or "login" in text or "token" in text:
            hint["repair_hint"] = "Codex CLI needs authentication before model tests can succeed."
    return hint


_openclaw_diag_cache = {"ts": 0.0, "data": None}


def _openclaw_runtime_diagnosis() -> dict:
    """Best-effort OpenClaw diagnosis for operator-facing failures."""
    now = time.time()
    cached = _openclaw_diag_cache.get("data")
    if cached and (now - float(_openclaw_diag_cache.get("ts") or 0)) < 30:
        return cached

    diag = {
        "gateway_running": False,
        "gateway_listening": False,
        "node_version": "",
        "issues": [],
        "doctor_summary": [],
        "paired_devices": 0,
        "pending_devices": 0,
        "pairing_temp_files": 0,
        "service_restart_loop": False,
        "token_mismatch": False,
        "log_path": "",
        "duplicate_service_units": False,
        "service_unit_paths": [],
        "recent_agent_success": False,
        "recent_agent_failure": False,
    }

    try:
        r = subprocess.run(["pgrep", "-f", "openclaw-gateway"], capture_output=True, text=True, timeout=3)
        diag["gateway_running"] = (r.returncode == 0 and bool((r.stdout or "").strip()))
        if not diag["gateway_running"]:
            diag["issues"].append("gateway_not_running")
    except Exception:
        diag["issues"].append("gateway_status_unknown")

    try:
        settings = _openclaw_gateway_settings()
        with socket.create_connection((str(settings.get("host") or "127.0.0.1"), int(settings.get("port") or 18789)), timeout=1.0):
            diag["gateway_listening"] = True
    except Exception:
        diag["gateway_listening"] = False

    try:
        node_r = subprocess.run(["node", "-v"], capture_output=True, text=True, timeout=3, env=_agent_env())
        node_ver = (node_r.stdout or node_r.stderr or "").strip()
        diag["node_version"] = node_ver
        m = re.search(r"v?(\d+)", node_ver)
        if m and int(m.group(1)) < 22:
            diag["issues"].append("node_below_22")
    except Exception:
        diag["issues"].append("node_version_unknown")

    oc_bin = _resolve_cli("openclaw")
    if oc_bin:
        try:
            dr = subprocess.run([oc_bin, "doctor"], capture_output=True, text=True, timeout=20, env=_agent_env(), cwd=str(Path.home()))
            out = (dr.stdout or "") + "\n" + (dr.stderr or "")
            for raw in out.splitlines():
                line = raw.strip()
                if not line:
                    continue
                if "Gateway not running" in line:
                    diag["issues"].append("doctor_gateway_not_running")
                    diag["doctor_summary"].append("Doctor reports gateway not running.")
                elif "below the required Node 22+" in line:
                    diag["issues"].append("doctor_node_requirement")
                    diag["doctor_summary"].append("Doctor reports Node below required 22+ runtime.")
                elif "embedded run agent end" in line and "timed out" in line.lower():
                    diag["issues"].append("embedded_timeout")
                    diag["doctor_summary"].append("Embedded fallback timed out.")
        except subprocess.TimeoutExpired:
            diag["issues"].append("doctor_timeout")
            diag["doctor_summary"].append("OpenClaw doctor timed out.")
        except Exception:
            diag["issues"].append("doctor_failed")

    try:
        devices_dir = OPENCLAW_STATE_DIR / "devices"
        paired_path = devices_dir / "paired.json"
        pending_path = devices_dir / "pending.json"
        if paired_path.exists():
            paired_data = json.loads(paired_path.read_text(encoding="utf-8") or "{}")
            if isinstance(paired_data, dict):
                diag["paired_devices"] = len([k for k in paired_data.keys() if str(k).strip()])
        if pending_path.exists():
            pending_data = json.loads(pending_path.read_text(encoding="utf-8") or "{}")
            if isinstance(pending_data, dict):
                diag["pending_devices"] = len([k for k in pending_data.keys() if str(k).strip()])
        if devices_dir.exists():
            diag["pairing_temp_files"] = len(list(devices_dir.glob("*.tmp")))
        if diag["pending_devices"] > 0:
            diag["issues"].append("pairing_pending")
        if diag["paired_devices"] > 0 and not diag["gateway_running"]:
            diag["issues"].append("paired_but_gateway_down")
            diag["doctor_summary"].append("Paired devices exist but the gateway is not running.")
        if diag["pairing_temp_files"] > 0:
            diag["issues"].append("pairing_temp_files")
    except Exception as e:
        log.debug("OpenClaw pairing diagnosis failed: %s", e)

    unit_paths = [
        Path("/etc/systemd/system/openclaw-gateway.service"),
        Path.home() / ".config" / "systemd" / "user" / "openclaw-gateway.service",
    ]
    try:
        existing_units = [str(p) for p in unit_paths if p.exists()]
        diag["service_unit_paths"] = existing_units
    except Exception as e:
        log.debug("OpenClaw unit diagnosis failed: %s", e)

    try:
        log_dir = Path("/tmp/openclaw")
        log_path = log_dir / f"openclaw-{datetime.utcnow().strftime('%Y-%m-%d')}.log"
        if log_path.exists():
            diag["log_path"] = str(log_path)
            lines = log_path.read_text(encoding="utf-8", errors="replace").splitlines()[-160:]
            restart_times = []
            token_mismatch_times = []
            success_times = []
            failure_times = []
            now_dt = datetime.now(timezone.utc)
            for line in lines:
                low = line.lower()
                evt_time = None
                rec = None
                try:
                    rec = json.loads(line)
                    raw_time = ""
                    if isinstance(rec, dict):
                        raw_time = str(rec.get("time") or (rec.get("_meta") or {}).get("date") or "").strip()
                    if raw_time:
                        evt_time = datetime.fromisoformat(raw_time.replace("Z", "+00:00"))
                        if evt_time.tzinfo is None:
                            evt_time = evt_time.replace(tzinfo=timezone.utc)
                except Exception:
                    evt_time = None
                if evt_time and isinstance(rec, dict):
                    line0 = str(rec.get("0") or "")
                    if "\"status\": \"ok\"" in line0 and "\"summary\": \"completed\"" in line0:
                        success_times.append(evt_time)
                    if "\"stopReason\": \"error\"" in line0 or "embedded run agent end" in low and "iserror=true" in low:
                        failure_times.append(evt_time)
                if "token_mismatch" in low or "unauthorized" in low:
                    if evt_time:
                        token_mismatch_times.append(evt_time)
                if "reason=service restart" in low or "killing 1 stale gateway process(es) before restart" in low or "signal sigterm received" in low:
                    if evt_time:
                        restart_times.append(evt_time)
            recent_restarts = [ts for ts in restart_times if abs((now_dt - ts).total_seconds()) <= 90]
            recent_token_mismatch = [ts for ts in token_mismatch_times if abs((now_dt - ts).total_seconds()) <= 300]
            recent_success = [ts for ts in success_times if abs((now_dt - ts).total_seconds()) <= 300]
            recent_failure = [ts for ts in failure_times if abs((now_dt - ts).total_seconds()) <= 300]
            if recent_success:
                diag["recent_agent_success"] = True
            if recent_failure:
                diag["recent_agent_failure"] = True
            if len(recent_restarts) >= 2:
                diag["service_restart_loop"] = True
                diag["issues"].append("service_restart_loop")
                diag["doctor_summary"].append("Gateway is restarting itself every few seconds.")
            if len(diag.get("service_unit_paths") or []) >= 2 and recent_restarts:
                diag["duplicate_service_units"] = True
                diag["issues"].append("duplicate_service_units")
                diag["doctor_summary"].append("Competing OpenClaw service units likely caused the restart loop.")
            if recent_token_mismatch:
                diag["token_mismatch"] = True
                diag["issues"].append("token_mismatch")
                diag["doctor_summary"].append("Gateway auth token mismatch was seen in recent logs.")
            if recent_success and recent_failure:
                diag["issues"].append("agent_path_flaky")
                diag["doctor_summary"].append("Gateway is up, but agent runs are intermittent.")
    except Exception as e:
        log.debug("OpenClaw log diagnosis failed: %s", e)

    if diag["gateway_running"] or diag["gateway_listening"]:
        diag["issues"] = [issue for issue in diag["issues"] if issue != "doctor_gateway_not_running"]
        diag["doctor_summary"] = [msg for msg in diag["doctor_summary"] if "gateway not running" not in msg.lower()]
    if re.search(r"v?(22|23|24|25)\b", diag.get("node_version") or ""):
        diag["issues"] = [issue for issue in diag["issues"] if issue != "doctor_node_requirement"]
        diag["doctor_summary"] = [msg for msg in diag["doctor_summary"] if "node below required 22+" not in msg.lower()]

    # Normalize + dedupe
    diag["issues"] = sorted(set(diag["issues"]))
    diag["doctor_summary"] = list(dict.fromkeys(diag["doctor_summary"]))[:3]
    _openclaw_diag_cache["ts"] = now
    _openclaw_diag_cache["data"] = diag
    return diag


def _check_gateway_status() -> dict:
    """Check openclaw-gateway process state and detect rapid PID churn."""
    global _gw_pid_history
    now = time.time()
    pid = None
    try:
        r = subprocess.run(["pgrep", "-f", "openclaw-gateway"], capture_output=True, text=True, timeout=3)
        if r.returncode == 0:
            pids = []
            for line in (r.stdout or "").splitlines():
                line = line.strip()
                if line.isdigit():
                    pids.append(int(line))
            if pids:
                pid = max(pids)
    except Exception as e:
        log.debug("Gateway pgrep failed: %s", e)

    if pid is not None:
        if not _gw_pid_history or _gw_pid_history[-1][0] != pid:
            _gw_pid_history.append((pid, now))

    _gw_pid_history = [(p, ts) for (p, ts) in _gw_pid_history if (now - ts) <= 60]
    recent_pids = sorted({p for (p, _) in _gw_pid_history})
    restart_count_60s = len(recent_pids)
    crash_looping = restart_count_60s >= 3

    uptime_s = None
    if pid is not None:
        try:
            proc_stat = Path(f"/proc/{pid}/stat").read_text(encoding="utf-8", errors="replace").split()
            start_ticks = float(proc_stat[21])
            clk_tck = float(os.sysconf("SC_CLK_TCK"))
            sys_uptime = float(Path("/proc/uptime").read_text(encoding="utf-8").split()[0])
            boot_ts = now - sys_uptime
            proc_start_ts = boot_ts + (start_ticks / clk_tck)
            uptime_s = max(0.0, now - proc_start_ts)
        except Exception as e:
            log.debug("Gateway uptime parse failed: %s", e)

    version = _capabilities_cache.get("openclaw", {}).get("version")
    version_short = ""
    if version:
        version_short = str(version).splitlines()[0].strip()
        version_short = re.sub(r"^openclaw\s+", "", version_short, flags=re.IGNORECASE)
        version_short = version_short[:40]
    settings = _openclaw_gateway_settings()
    diagnosis = _openclaw_runtime_diagnosis()
    diag_summary = list(diagnosis.get("doctor_summary") or [])
    node_issue = any(issue in diagnosis.get("issues", []) for issue in ("node_below_22", "doctor_node_requirement"))
    repair_detail = " ".join(diag_summary or diagnosis.get("issues", []))
    if (diagnosis.get("gateway_running") or diagnosis.get("gateway_listening")) and diagnosis.get("recent_agent_failure"):
        if diagnosis.get("recent_agent_success"):
            repair_detail = "agent_path_flaky"
        else:
            repair_detail = "agent execution failed timeout"
    repair = _model_repair_hint("openclaw", repair_detail) if repair_detail.strip() else {}
    return {
        "ok": True,
        "running": pid is not None,
        "pid": pid,
        "uptime_s": uptime_s,
        "listening": bool(diagnosis.get("gateway_listening")),
        "crash_looping": crash_looping,
        "restart_count_60s": restart_count_60s,
        "version": version,
        "version_short": version_short,
        "host": settings.get("host"),
        "port": settings.get("port"),
        "config_source": settings.get("source"),
        "auth_configured": bool(settings.get("token")),
        "diagnosis_summary": diag_summary[:3],
        "node_issue": node_issue,
        "service_restart_loop": bool(diagnosis.get("service_restart_loop")),
        "token_mismatch": bool(diagnosis.get("token_mismatch")),
        "log_path": diagnosis.get("log_path", ""),
        "duplicate_service_units": bool(diagnosis.get("duplicate_service_units")),
        "service_unit_paths": list(diagnosis.get("service_unit_paths") or []),
        "paired_devices": int(diagnosis.get("paired_devices") or 0),
        "pending_devices": int(diagnosis.get("pending_devices") or 0),
        "recent_agent_success": bool(diagnosis.get("recent_agent_success")),
        "recent_agent_failure": bool(diagnosis.get("recent_agent_failure")),
        "repair_hint": repair.get("repair_hint", ""),
        "repair_cmd": repair.get("repair_cmd", ""),
        "followup_hint": repair.get("followup_hint", ""),
        "reinstall_cmd": repair.get("reinstall_cmd", ""),
    }


def _models_cache_fingerprint() -> str:
    try:
        cfg_stat = CONFIG_PATH.stat()
        cfg_fp = f"{cfg_stat.st_size}:{cfg_stat.st_mtime_ns}"
    except Exception:
        cfg_fp = "cfg:missing"
    cli_fp = "|".join(f"{bk}:{_cli_binary_fingerprints.get(bk, '')}" for bk in sorted(PROVIDER_REGISTRY))
    return f"{cfg_fp}|{cli_fp}"


def _lightweight_provider_available(name: str) -> bool:
    cap = _capabilities_cache.get(name) or {}
    if isinstance(cap, dict) and "ok" in cap:
        return bool(cap.get("ok"))
    if name == "ollama":
        return _resolve_cli("ollama") is not None
    return _resolve_cli(name) is not None


def _providers_payload(lightweight: bool = False) -> list:
    providers = []
    availability = {}
    if lightweight:
        for name in PROVIDER_REGISTRY:
            availability[name] = _lightweight_provider_available(name)
    else:
        import concurrent.futures as _cf
        with _cf.ThreadPoolExecutor(max_workers=min(5, len(PROVIDER_REGISTRY))) as ex:
            future_map = {ex.submit(_probe_provider, name): name for name in PROVIDER_REGISTRY}
            for fut, name in ((f, future_map[f]) for f in future_map):
                try:
                    availability[name] = bool(fut.result(timeout=4))
                except Exception:
                    availability[name] = False
    for name, info in PROVIDER_REGISTRY.items():
        _meta = _backend_meta(name)
        available = availability.get(name)
        if available is None:
            available = _probe_provider(name)
        providers.append({
            "id": name,
            "available": available,
            "type": info["type"],
            "label": info["label"],
            "description": _meta.get("description", ""),
            "install_hint": INSTALL_HINTS.get(name, ""),
        })
    return providers


def _models_activity_payload(include_recent: bool = True) -> dict:
    import time as _act_t
    _act_now = _act_t.time()
    _act_since = _act_now - 86400
    activity = {}
    try:
        _act_conn = _db_conn()
        _stale_cutoff = _act_now - 600
        _act_conn.execute(
            "UPDATE agent_messages SET status='failed' "
            "WHERE status='in_progress' AND created_at<?",
            (_stale_cutoff,)
        )
        _act_conn.commit()
        for _bk in PROVIDER_REGISTRY:
            _act_active = _act_conn.execute(
                "SELECT run_id, message, created_at FROM agent_messages "
                "WHERE to_agent=? AND status='in_progress' ORDER BY created_at DESC LIMIT 3",
                (_bk,)
            ).fetchall()
            _act_stats = _act_conn.execute(
                "SELECT COUNT(*) as total, "
                "SUM(CASE WHEN status='complete' THEN 1 ELSE 0 END) as complete, "
                "SUM(CASE WHEN status='failed' THEN 1 ELSE 0 END) as failed, "
                "AVG(CASE WHEN status='complete' THEN duration_ms END) as avg_ms "
                "FROM agent_messages WHERE to_agent=? AND created_at>?",
                (_bk, _act_since)
            ).fetchone()
            _act_recent = []
            if include_recent:
                _act_recent = _act_conn.execute(
                    "SELECT run_id, status, substr(message,1,80) as preview, "
                    "duration_ms, created_at FROM agent_messages "
                    "WHERE to_agent=? ORDER BY created_at DESC LIMIT 5",
                    (_bk,)
                ).fetchall()
            activity[_bk] = {
                "active": [{"run_id": r[0], "prompt": r[1][:80] if r[1] else "", "started_at": r[2]} for r in _act_active],
                "stats": {
                    "total": _act_stats[0] or 0,
                    "complete": _act_stats[1] or 0,
                    "failed": _act_stats[2] or 0,
                    "avg_ms": int(_act_stats[3] or 0),
                },
                "recent": [{"run_id": r[0], "status": r[1], "preview": r[2] or "",
                           "duration_ms": r[3] or 0, "created_at": r[4]} for r in _act_recent],
                "_partial": not include_recent,
            }
        _act_conn.close()
    except Exception:
        pass
    return activity


def _models_available_payload(lightweight: bool = False) -> dict:
    prefs = _config.get("preferences", {})
    active_models = prefs.get("active_models", {})
    backends_out = {}
    import concurrent.futures as _avail_cf
    _bk_list = list(PROVIDER_REGISTRY.keys())
    def _fetch_bk_models(bk):
        choice = active_models.get(bk, "auto")
        cached_models = _backend_model_cache["data"].get(bk) or []
        if lightweight and cached_models:
            models = cached_models
        elif lightweight:
            resolved_guess = choice if choice != "auto" else ""
            catalog_seed = []
            if resolved_guess:
                catalog_seed.append({"id": resolved_guess, "name": _model_display_name(resolved_guess) or resolved_guess})
            models = _unique_model_catalog(catalog_seed, resolved_guess)
        else:
            models = _get_available_models(bk)
        resolved = _get_active_model(bk) if not lightweight else (choice if choice != "auto" else (models[0]["id"] if models else ""))
        catalog = ([{"id": "auto", "name": "Auto"}] + models) if len(models) > 0 else [{"id": "auto", "name": "Auto"}]
        return bk, {"active": choice, "resolved": resolved, "models": catalog}
    if lightweight:
        for bk in _bk_list:
            _, data = _fetch_bk_models(bk)
            backends_out[bk] = data
    else:
        with _avail_cf.ThreadPoolExecutor(max_workers=max(1, min(len(_bk_list), 8))) as _avail_ex:
            for bk, data in _avail_ex.map(_fetch_bk_models, _bk_list):
                backends_out[bk] = data
    return backends_out


def _models_snapshot(force_versions: bool = False) -> dict:
    _refresh_cli_cache_fingerprints()
    # Cap checks moved to background — too slow for HTTP handler (8s+)
    now = time.time()
    fp = _models_cache_fingerprint()
    if (not force_versions and _models_snapshot_cache.get("data")
            and _models_snapshot_cache.get("fp") == fp
            and (now - float(_models_snapshot_cache.get("ts") or 0.0)) < 120.0):
        return dict(_models_snapshot_cache["data"])
    payload = {
        "ok": True,
        "providers": _providers_payload(),
        "activity": {},
        "backends": _models_available_payload(),
        "benchmarks": _bridge_benchmark_summary(86400),
        "scheduler": _bridge_scheduler_summary(),
        "versions": _probe_backend_versions(force=force_versions),
        "runtimes": {bk: _backend_runtime_info(bk) for bk in PROVIDER_REGISTRY},
    }
    _models_snapshot_cache["data"] = dict(payload)
    _models_snapshot_cache["ts"] = now
    _models_snapshot_cache["fp"] = fp
    return payload


def _models_bootstrap() -> dict:
    _refresh_cli_cache_fingerprints()
    # Cap checks moved to background — too slow for HTTP handler
    now = time.time()
    fp = _models_cache_fingerprint()
    if (_models_bootstrap_cache.get("data")
            and _models_bootstrap_cache.get("fp") == fp
            and (now - float(_models_bootstrap_cache.get("ts") or 0.0)) < 120.0):
        return dict(_models_bootstrap_cache["data"])
    payload = {
        "ok": True,
        "providers": _providers_payload(lightweight=True),
        "activity": {},
        "backends": _models_available_payload(lightweight=True),
        "benchmarks": _bridge_benchmark_summary(86400),
        "scheduler": _bridge_scheduler_summary(),
        "versions": _bootstrap_backend_versions(),
        "runtimes": {bk: _backend_runtime_info(bk) for bk in PROVIDER_REGISTRY},
    }
    _models_bootstrap_cache["data"] = dict(payload)
    _models_bootstrap_cache["ts"] = now
    _models_bootstrap_cache["fp"] = fp
    return payload


def _gateway_stop() -> dict:
    """Stop gateway process; supervisor/TUI may respawn it depending on host setup."""
    try:
        subprocess.run(["pkill", "-f", "openclaw-gateway"], timeout=5, capture_output=True)
        return {"ok": True, "message": "Gateway stop signal sent"}
    except Exception as e:
        return {"ok": False, "error": str(e)[:200]}


def _gateway_restart() -> dict:
    """Restart gateway by killing process; runtime supervisor should respawn it."""
    try:
        subprocess.run(["pkill", "-f", "openclaw-gateway"], timeout=5, capture_output=True)
        return {"ok": True, "message": "Gateway restart signal sent"}
    except Exception as e:
        return {"ok": False, "error": str(e)[:200]}


def _test_model_connectivity(backend_id: str, model: str = "") -> dict:
    """Test connectivity for a specific backend + model. All config from porter_config.json."""
    import urllib.request

    backend_id = str(backend_id or "").strip()
    if not backend_id:
        return {"ok": False, "model": "", "error": "backend required"}

    backend = backend_id.lower()
    alias = {"openclaw-gateway": "openclaw", "gemini_cli": "gemini", "claude_code": "claude"}
    backend = alias.get(backend, backend)

    # Resolve "auto" to actual model
    if not model or model == "auto":
        model = _get_active_model(backend) or ""
    bridge_meta = _bridge_runtime_semantics(backend, model)

    t0 = time.time()
    try:
        if backend == "openclaw":
            # OpenClaw gateway is WebSocket — use CLI, not HTTP
            oc_bin = _resolve_cli("openclaw")
            if not oc_bin:
                result = {"ok": False, "backend": backend, "model": model, "error": "openclaw CLI not found"}
                result.update(_model_repair_hint(backend, result["error"]))
                return result
            cmd = [oc_bin, "agent", "--agent", "main", "--message", "Reply with just the word OK", "--json", "--timeout", "45"]
            attempts = []
            for attempt in range(2):
                r = subprocess.run(cmd, capture_output=True, text=True, timeout=55, env=_agent_env(), cwd=str(Path.home()))
                out = (r.stdout or "").strip()
                text = ""
                latest_obj = None
                # Try parsing entire stdout as single JSON first (pretty-printed output)
                try:
                    _whole = json.loads(out)
                    if isinstance(_whole, dict):
                        latest_obj = _whole
                except Exception:
                    pass
                # Fall back to line-by-line JSONL parsing
                if latest_obj is None:
                    for line in out.split("\n"):
                        if not line.strip():
                            continue
                        try:
                            evt = json.loads(line)
                            if isinstance(evt, dict):
                                latest_obj = evt
                            if evt.get("type") == "item.completed":
                                item = evt.get("item", {})
                                if item.get("type") == "agent_message":
                                    text = item.get("text", "") or ""
                        except Exception:
                            continue
                if not text and isinstance(latest_obj, dict):
                    result_obj = latest_obj.get("result", {}) if isinstance(latest_obj.get("result"), dict) else {}
                    payloads = result_obj.get("payloads", []) if isinstance(result_obj, dict) else []
                    if isinstance(payloads, list):
                        for payload in payloads:
                            if isinstance(payload, dict) and str(payload.get("text", "")).strip():
                                text = str(payload.get("text", "")).strip()
                                break
                    if not text and str(result_obj.get("text", "")).strip():
                        text = str(result_obj.get("text", "")).strip()
                    if not text and str(latest_obj.get("summary", "")).strip().lower() == "completed" and str(latest_obj.get("status", "")).strip().lower() == "ok":
                        text = "OK"
                if text:
                    latency_ms = int((time.time() - t0) * 1000)
                    result = {"ok": True, "model": model, "response": text.strip()[:200], "latency_ms": latency_ms, "bridge": bridge_meta}
                    if attempt:
                        result["execution_state"] = "flaky"
                        result["attempts"] = attempt + 1
                    else:
                        result["execution_state"] = "healthy"
                    return result
                err = ""
                for line in out.split("\n"):
                    try:
                        evt = json.loads(line)
                        if evt.get("type") in ("error", "turn.failed"):
                            err = evt.get("message", "") or str(evt.get("error", {}).get("message", ""))
                    except Exception:
                        continue
                if not err and isinstance(latest_obj, dict):
                    if str(latest_obj.get("status", "")).strip().lower() not in ("", "ok"):
                        err = str(latest_obj.get("summary", "") or latest_obj.get("status", "") or "")
                if not err:
                    err = (r.stderr or "").strip()[:200] or "No response from gateway"
                attempts.append({
                    "error": err[:200],
                    "stderr": (r.stderr or "").strip()[:500],
                    "transient": ("1006" in err.lower() or "timed out" in err.lower() or "timeout" in err.lower() or "1006" in (r.stderr or "").lower()),
                })
                if not attempts[-1]["transient"] or attempt == 1:
                    break
                time.sleep(1.0)
            last = attempts[-1] if attempts else {"error": "No response from gateway", "stderr": ""}
            log.warning("Model test fail [openclaw]: model=%s err=%s stderr=%s", model, last.get("error", ""), last.get("stderr", ""))
            result = {"ok": False, "backend": backend, "model": model, "error": last.get("error", "")[:200], "execution_state": "broken", "attempts": len(attempts), "bridge": bridge_meta}
            if any(a.get("transient") for a in attempts):
                result["execution_state"] = "flaky"
            result.update(_model_repair_hint(backend, (last.get("stderr", "") or "") + "\n" + last.get("error", "")))
            diagnosis = _openclaw_runtime_diagnosis()
            if diagnosis.get("doctor_summary"):
                result["diagnosis"] = diagnosis
            if diagnosis.get("gateway_running") or diagnosis.get("gateway_listening"):
                if result.get("execution_state") == "flaky":
                    result["repair_hint"] = "Gateway looks healthy, but real OpenClaw agent runs are intermittent. Retry once and inspect gateway logs if 1006/timeouts continue."
                else:
                    result["repair_hint"] = "Gateway is up, but real OpenClaw agent execution failed. Inspect the active gateway service and last stderr."
            elif "embedded_timeout" in diagnosis.get("issues", []):
                result["repair_hint"] = "OpenClaw gateway failed and embedded fallback also timed out. This is runtime breakage, not just a slow model."
            return result

        if backend == "codex":
            cdx = _resolve_cli("codex")
            if not cdx:
                result = {"ok": False, "backend": backend, "model": model, "error": "codex CLI not found"}
                result.update(_model_repair_hint(backend, result["error"]))
                return result
            _cdx_model = model or "gpt-5.4"
            cmd = [cdx, "exec", "--ephemeral", "--json", "--skip-git-repo-check",
                   "-m", _cdx_model, "Reply with just the word OK"]
            r = subprocess.run(cmd, capture_output=True, text=True, timeout=30, env=_agent_env(), cwd=str(Path.home()))
            latency_ms = int((time.time() - t0) * 1000)
            text = ""
            for line in (r.stdout or "").strip().split("\n"):
                if not line.strip():
                    continue
                try:
                    evt = json.loads(line)
                    if evt.get("type") == "item.completed":
                        item = evt.get("item", {})
                        if item.get("type") == "agent_message":
                            msg = item.get("text", "") or ""
                            if not msg:
                                parts = [p.get("text", "") for p in (item.get("content", []) or []) if isinstance(p, dict) and p.get("text")]
                                if parts:
                                    msg = "".join(parts).strip()
                            if msg:
                                text = msg
                except Exception:
                    continue
            if text:
                return {"ok": True, "model": model, "response": text.strip()[:200], "latency_ms": latency_ms, "bridge": bridge_meta}
            _cdx_err = (r.stderr or "").strip()[:200] or "Codex returned no text"
            log.warning("Model test fail [codex]: model=%s err=%s stdout=%s", model, _cdx_err, (r.stdout or "").strip()[:500])
            result = {"ok": False, "backend": backend, "model": model, "error": _cdx_err}
            result.update(_model_repair_hint(backend, _cdx_err))
            return result

        if backend == "ollama":
            bc = _config.get("backend_config", {}).get("ollama", {})
            _oll_host = bc.get("host", "127.0.0.1")
            _oll_port = bc.get("port", 11434)
            model_name = model or "qwen2.5-coder:1.5b"
            payload = {"model": model_name, "prompt": "Reply OK", "stream": False}
            req = urllib.request.Request(
                f"http://{_oll_host}:{_oll_port}/api/generate",
                data=json.dumps(payload).encode("utf-8"),
                headers={"Content-Type": "application/json"},
                method="POST",
            )
            with urllib.request.urlopen(req, timeout=15) as resp:
                body = json.loads(resp.read().decode("utf-8", errors="replace") or "{}")
            latency_ms = int((time.time() - t0) * 1000)
            return {"ok": True, "backend": backend, "model": model, "response": str(body.get("response", "OK")).strip()[:200], "latency_ms": latency_ms, "bridge": bridge_meta}

        if backend == "gemini":
            gem = _resolve_cli("gemini")
            if not gem:
                result = {"ok": False, "backend": backend, "model": model, "error": "gemini CLI not found"}
                result.update(_model_repair_hint(backend, result["error"]))
                return result
            runtime = _backend_runtime_info("gemini")
            _gem_model = str(model or "").strip()
            if not _gem_model or _gem_model in ("auto", "gemini"):
                _gem_model = runtime.get("recommended_smoke_model") or _get_active_model("gemini") or "gemini-2.5-flash"
            _gem_model = _normalize_gemini_model_id(_gem_model, runtime.get("auth_mode", ""))
            cmd = [gem]
            if runtime.get("supports_headless"):
                cmd.extend(["-p", "Reply with just OK", "-y"])
            else:
                cmd.append("Reply with just OK")
            if runtime.get("supports_model_flag") and _gem_model:
                cmd.extend(["-m", _gem_model])
            if runtime.get("supports_json_output"):
                cmd.extend(["--output-format", "json"])
            _gem_env = _agent_env()
            _gem_env["GEMINI_CLI_YOLO"] = "1"  # suppress YOLO prompts
            _gem_timeout = 75 if "preview" in str(_gem_model or "").lower() else 45
            r = subprocess.run(cmd, capture_output=True, text=True, timeout=_gem_timeout, env=_gem_env, cwd=str(Path.home()))
            _gem_stdout = (r.stdout or "").strip()
            if "Please visit the following URL to authorize" in _gem_stdout or "accounts.google.com/o/oauth2" in _gem_stdout:
                _gem_fail_msg = "Gemini CLI requires OAuth re-authorization"
                result = {"ok": False, "backend": backend, "model": model, "error": _gem_fail_msg, "runtime": {"auth_mode": runtime.get("auth_mode", ""), "resolved_model": _gem_model}, "bridge": bridge_meta}
                result.update(_model_repair_hint(backend, "auth oauth reauthorize"))
                result["repair_hint"] = "Gemini CLI is asking for OAuth login again. Re-authenticate Gemini before relying on model tests."
                return result
            if r.returncode != 0:
                _gem_err = (r.stderr or "").strip()
                # Filter out YOLO mode info lines
                _gem_err = "\n".join(l for l in _gem_err.split("\n") if "YOLO" not in l and "cached credentials" not in l.lower()).strip()
                _gem_fail_msg = (_gem_err or _gem_stdout or "Gemini failed").strip()[:200]
                log.warning("Model test fail [gemini]: model=%s rc=%s err=%s stdout=%s", model, r.returncode, _gem_fail_msg, (r.stdout or "").strip()[:500])
                result = {"ok": False, "backend": backend, "model": model, "error": _gem_fail_msg, "bridge": bridge_meta}
                result.update(_model_repair_hint(backend, _gem_fail_msg))
                result["runtime"] = {"auth_mode": runtime.get("auth_mode", ""), "resolved_model": _gem_model}
                return result
            latency_ms = int((time.time() - t0) * 1000)
            _gem_text = _gem_stdout
            if runtime.get("supports_json_output"):
                try:
                    payload = json.loads(_gem_text)
                    if isinstance(payload, dict):
                        _gem_text = str(payload.get("text") or payload.get("response") or payload.get("output") or payload.get("result") or "OK")
                except Exception:
                    pass
            return {"ok": True, "backend": backend, "model": model, "response": _gem_text.strip()[:200] or "OK", "latency_ms": latency_ms, "runtime": {"auth_mode": runtime.get("auth_mode", ""), "resolved_model": _gem_model}, "bridge": bridge_meta}

        if backend == "claude":
            claude_bin = _resolve_cli("claude")
            if not claude_bin:
                result = {"ok": False, "backend": backend, "model": model, "error": "claude CLI not found"}
                result.update(_model_repair_hint(backend, result["error"]))
                return result
            runtime = _backend_runtime_info("claude")
            cmd = [claude_bin]
            if runtime.get("supports_headless"):
                cmd.extend(["-p", "Reply with just OK"])
            else:
                cmd.append("Reply with just OK")
            if runtime.get("supports_model_flag") and model and model != "auto" and model != "claude":
                cmd.extend(["--model", model])
            if runtime.get("supports_json_output"):
                cmd.extend(["--output-format", "json"])
            # Unset CLAUDECODE to allow nested invocation from within Claude Code
            _env = _agent_env()
            _env.pop("CLAUDECODE", None)
            r = subprocess.run(cmd, capture_output=True, text=True, timeout=30, env=_env, cwd=str(Path.home()))
            if r.returncode != 0:
                _cl_fail_msg = (r.stderr or r.stdout or "Claude failed").strip()[:200]
                log.warning("Model test fail [claude]: model=%s rc=%s err=%s stdout=%s", model, r.returncode, _cl_fail_msg, (r.stdout or "").strip()[:500])
                result = {"ok": False, "backend": backend, "model": model, "error": _cl_fail_msg, "bridge": bridge_meta}
                result.update(_model_repair_hint(backend, _cl_fail_msg))
                return result
            latency_ms = int((time.time() - t0) * 1000)
            _cl_text = (r.stdout or "OK").strip()
            if runtime.get("supports_json_output"):
                try:
                    payload = json.loads(_cl_text)
                    if isinstance(payload, dict):
                        _cl_text = str(payload.get("result") or payload.get("text") or payload.get("output") or "OK")
                except Exception:
                    pass
            return {"ok": True, "backend": backend, "model": model, "response": _cl_text[:200], "latency_ms": latency_ms, "bridge": bridge_meta}

        result = {"ok": False, "backend": backend, "model": model, "error": f"Unknown backend: {backend}", "bridge": bridge_meta}
        result.update(_model_repair_hint(backend, result["error"]))
        return result
    except subprocess.TimeoutExpired:
        log.warning("Model test timeout: backend=%s model=%s", backend, model)
        result = {"ok": False, "backend": backend, "model": model, "error": "Timed out", "bridge": bridge_meta}
        result.update(_model_repair_hint(backend, result["error"]))
        return result
    except Exception as e:
        log.warning("Model test error: backend=%s model=%s err=%s", backend, model, str(e))
        result = {"ok": False, "backend": backend, "model": model, "error": str(e)[:200], "bridge": bridge_meta}
        result.update(_model_repair_hint(backend, result["error"]))
        return result


# ── Active Streams (for live trace) ───────────────────────────────────────
_active_streams = {}  # {run_id: {"backend": str, "chunks": [], "started_at": float}}
_streams_lock = __import__("threading").Lock()
# ── Delegation log ─────────────────────────────────────────────────────────
_delegation_log = []  # List of recent delegations (max 50)
_delegation_lock = _threading.Lock()

def _log_delegation(backend, message, result, duration_ms):
    """Record a delegation to the log."""
    import time as _t
    entry = {
        "ts": _t.time(),
        "backend": backend,
        "prompt": message[:100],
        "ok": result.get("ok", False),
        "model": result.get("model", ""),
        "duration_ms": duration_ms,
        "tokens": result.get("tokens", {}).get("total", 0),
    }
    with _delegation_lock:
        _delegation_log.append(entry)
        if len(_delegation_log) > 50:
            _delegation_log.pop(0)


def _ranked_route():
    """Route based on user-configured model rankings.
    Returns (backend, model) tuple, or None if no rankings configured.
    """
    prefs = _config.get("preferences", {})
    rankings = prefs.get("model_rankings", {})
    if not rankings:
        return None
    # rankings is {model_id: rank_int} where 1=highest priority
    # Map model_id patterns to backends
    model_backend = {
        "gpt-5.4": "openclaw",
        "openclaw": "openclaw",
        "claude": "claude",
        "gemini": "gemini",
        "ollama": "ollama",
        "codex": "codex",
        "qwen": "ollama",
    }
    # Sort by rank (lowest number = highest priority)
    sorted_models = sorted(rankings.items(), key=lambda x: int(x[1]) if str(x[1]).isdigit() else 99)
    for model_id, rank in sorted_models:
        mid = model_id.lower()
        for pattern, backend in model_backend.items():
            if pattern in mid:
                return (backend, None)
    return None


_DEFAULT_FALLBACK_CHAIN = ["codex", "claude", "gemini", "openclaw", "ollama"]
_backend_breakers = {}
_BRIDGE_DEFAULT_BACKEND_LIMITS = {"openclaw": 1, "claude": 2, "gemini": 2, "codex": 2, "ollama": 2}
_BRIDGE_DEFAULT_MODEL_LIMITS = {"openclaw": 1, "claude": 1, "gemini": 1, "codex": 2, "ollama": 1}
_bridge_scheduler_state = {
    "running_by_backend": {},
    "running_by_lane": {},
    "waiting_by_backend": {},
    "waiting_by_lane": {},
    "queue": [],
    "stats": {},
}
_bridge_scheduler_lock = threading.Lock()
_bridge_scheduler_cond = threading.Condition(_bridge_scheduler_lock)


def _backend_breaker_state(backend: str) -> dict:
    bk = str(backend or "").strip().lower()
    if not bk:
        return {"failures": 0, "open_until": 0.0, "last_error": ""}
    state = _backend_breakers.get(bk)
    if not state:
        state = {"failures": 0, "open_until": 0.0, "last_error": "", "last_failure_at": 0.0, "last_success_at": 0.0}
        _backend_breakers[bk] = state
    return state


def _record_backend_dispatch_result(backend: str, ok: bool, error: str = "") -> None:
    state = _backend_breaker_state(backend)
    now = time.time()
    if ok:
        state["failures"] = 0
        state["open_until"] = 0.0
        state["last_error"] = ""
        state["last_success_at"] = now
        return
    if state.get("last_failure_at") and (now - float(state.get("last_failure_at") or 0)) > 300:
        state["failures"] = 0
    state["failures"] = int(state.get("failures") or 0) + 1
    state["last_failure_at"] = now
    state["last_error"] = str(error or "")[:240]
    if state["failures"] >= 3:
        state["open_until"] = now + 90.0


def _backend_is_circuit_open(backend: str) -> bool:
    state = _backend_breaker_state(backend)
    return float(state.get("open_until") or 0) > time.time()


def _bridge_scheduler_limits(backend: str, model: str = "") -> dict:
    prefs = _config.get("preferences", {}) if isinstance(_config, dict) else {}
    sched = prefs.get("bridge_scheduler", {}) if isinstance(prefs.get("bridge_scheduler", {}), dict) else {}
    backend_limits = sched.get("backend_limits", {}) if isinstance(sched.get("backend_limits", {}), dict) else {}
    model_limits = sched.get("model_limits", {}) if isinstance(sched.get("model_limits", {}), dict) else {}
    bk = str(backend or "").strip().lower()
    lane_model = str(model or "").strip() or "_default"
    backend_limit = max(1, int(backend_limits.get(bk, _BRIDGE_DEFAULT_BACKEND_LIMITS.get(bk, 2)) or 1))
    model_limit = max(1, int(model_limits.get(bk, _BRIDGE_DEFAULT_MODEL_LIMITS.get(bk, 1)) or 1))
    return {"backend_limit": backend_limit, "model_limit": model_limit, "lane_key": f"{bk}::{lane_model}", "lane_model": lane_model}


def _bridge_scheduler_snapshot() -> dict:
    with _bridge_scheduler_lock:
        return {
            "running_by_backend": dict(_bridge_scheduler_state["running_by_backend"]),
            "running_by_lane": dict(_bridge_scheduler_state["running_by_lane"]),
            "waiting_by_backend": dict(_bridge_scheduler_state["waiting_by_backend"]),
            "waiting_by_lane": dict(_bridge_scheduler_state["waiting_by_lane"]),
            "queue": list(_bridge_scheduler_state["queue"][-50:]),
            "stats": dict(_bridge_scheduler_state["stats"]),
        }


def _bridge_scheduler_backend_pressure(backend: str) -> dict:
    snap = _bridge_scheduler_snapshot()
    limits = _bridge_scheduler_limits(backend, "")
    running = int(snap["running_by_backend"].get(backend, 0))
    waiting = int(snap["waiting_by_backend"].get(backend, 0))
    stats = snap["stats"].get(backend, {}) if isinstance(snap.get("stats", {}), dict) else {}
    return {
        "running": running,
        "waiting": waiting,
        "backend_limit": int(limits["backend_limit"]),
        "saturated": running >= int(limits["backend_limit"]),
        "avg_wait_ms": int(stats.get("avg_wait_ms", 0) or 0),
        "max_wait_ms": int(stats.get("max_wait_ms", 0) or 0),
    }


def _bridge_scheduler_summary() -> dict:
    snap = _bridge_scheduler_snapshot()
    out = {}
    for backend in PROVIDER_REGISTRY:
        pressure = _bridge_scheduler_backend_pressure(backend)
        stats = snap.get("stats", {}).get(backend, {}) if isinstance(snap.get("stats", {}), dict) else {}
        out[backend] = {
            **pressure,
            "admissions": int(stats.get("admissions", 0) or 0),
        }
    return out


def _bridge_scheduler_acquire(backend: str, model: str, run_id: str = "", timeout_s: int = 120) -> dict:
    now = time.time()
    limits = _bridge_scheduler_limits(backend, model)
    lane_key = limits["lane_key"]
    ticket = {"run_id": str(run_id or ""), "backend": backend, "lane_key": lane_key, "queued_at": now}
    deadline = now + max(30, int(timeout_s or 120) + 30)
    with _bridge_scheduler_cond:
        _bridge_scheduler_state["queue"].append(ticket)
        _bridge_scheduler_state["waiting_by_backend"][backend] = int(_bridge_scheduler_state["waiting_by_backend"].get(backend, 0)) + 1
        _bridge_scheduler_state["waiting_by_lane"][lane_key] = int(_bridge_scheduler_state["waiting_by_lane"].get(lane_key, 0)) + 1
        _emit_event("bridge:queued", {"run_id": run_id, "backend": backend, "model": model or "", "lane_key": lane_key})
        while True:
            backend_running = int(_bridge_scheduler_state["running_by_backend"].get(backend, 0))
            lane_running = int(_bridge_scheduler_state["running_by_lane"].get(lane_key, 0))
            queue_head = next((q for q in _bridge_scheduler_state["queue"] if q.get("backend") == backend and q.get("lane_key") == lane_key), None)
            can_run = (
                queue_head is ticket
                and backend_running < int(limits["backend_limit"])
                and lane_running < int(limits["model_limit"])
            )
            if can_run:
                _bridge_scheduler_state["queue"] = [q for q in _bridge_scheduler_state["queue"] if q is not ticket]
                _bridge_scheduler_state["waiting_by_backend"][backend] = max(0, int(_bridge_scheduler_state["waiting_by_backend"].get(backend, 0)) - 1)
                _bridge_scheduler_state["waiting_by_lane"][lane_key] = max(0, int(_bridge_scheduler_state["waiting_by_lane"].get(lane_key, 0)) - 1)
                _bridge_scheduler_state["running_by_backend"][backend] = backend_running + 1
                _bridge_scheduler_state["running_by_lane"][lane_key] = lane_running + 1
                wait_ms = int((time.time() - now) * 1000)
                stats = _bridge_scheduler_state["stats"].setdefault(backend, {"admissions": 0, "total_wait_ms": 0, "avg_wait_ms": 0, "max_wait_ms": 0})
                stats["admissions"] = int(stats.get("admissions", 0)) + 1
                stats["total_wait_ms"] = int(stats.get("total_wait_ms", 0)) + wait_ms
                stats["avg_wait_ms"] = int(stats["total_wait_ms"] / max(1, stats["admissions"]))
                stats["max_wait_ms"] = max(int(stats.get("max_wait_ms", 0)), wait_ms)
                if wait_ms > 0:
                    _emit_event("bridge:admit", {"run_id": run_id, "backend": backend, "model": model or "", "wait_ms": wait_ms})
                return {"wait_ms": wait_ms, "lane_key": lane_key, "backend_limit": limits["backend_limit"], "model_limit": limits["model_limit"]}
            remaining = deadline - time.time()
            if remaining <= 0:
                _bridge_scheduler_state["queue"] = [q for q in _bridge_scheduler_state["queue"] if q is not ticket]
                _bridge_scheduler_state["waiting_by_backend"][backend] = max(0, int(_bridge_scheduler_state["waiting_by_backend"].get(backend, 0)) - 1)
                _bridge_scheduler_state["waiting_by_lane"][lane_key] = max(0, int(_bridge_scheduler_state["waiting_by_lane"].get(lane_key, 0)) - 1)
                raise TimeoutError(f"Bridge queue timeout for {backend}")
            _bridge_scheduler_cond.wait(timeout=min(1.0, remaining))


def _bridge_scheduler_release(backend: str, lane_key: str) -> None:
    with _bridge_scheduler_cond:
        _bridge_scheduler_state["running_by_backend"][backend] = max(0, int(_bridge_scheduler_state["running_by_backend"].get(backend, 0)) - 1)
        _bridge_scheduler_state["running_by_lane"][lane_key] = max(0, int(_bridge_scheduler_state["running_by_lane"].get(lane_key, 0)) - 1)
        _bridge_scheduler_cond.notify_all()

def _resolve_with_fallback(preferred, message=""):
    """Try preferred backend; if unavailable, walk fallback chain.
    Returns (backend, model) tuple.
    """
    if _probe_provider(preferred) and not _backend_is_circuit_open(preferred):
        mlog.emit("info", "routing", "route.decision", f"Route → {preferred} (preferred, available)", backend=preferred)
        return (preferred, None)
    # Walk fallback chain
    prefs = _config.get("preferences", {})
    chain = prefs.get("fallback_chain", _DEFAULT_FALLBACK_CHAIN)
    if not isinstance(chain, list) or not chain:
        chain = _DEFAULT_FALLBACK_CHAIN
    for backend in chain:
        if backend == preferred:
            continue
        if _probe_provider(backend) and not _backend_is_circuit_open(backend):
            mlog.emit("warn", "routing", "route.fallback",
                       f"Route fallback: {preferred} unavailable → {backend}",
                       preferred=preferred, fallback=backend)
            return (backend, None)
    # Nothing available — return preferred anyway (let dispatch handle the error)
    mlog.emit("error", "routing", "route.no_backend",
               f"No available backends (tried {preferred} + chain)", preferred=preferred)
    return (preferred, None)


def _project_route_hint(project_id="", task_id="", persona_id=""):
    """Return a project/task-aware preferred backend when one is obvious."""
    task = _task_by_id(task_id)
    if task:
        assigned_persona = str(task.get("assigned_persona_id") or "").strip()
        if assigned_persona:
            persona = _persona_by_id(assigned_persona)
            if _persona_is_orchestrator_only(persona):
                return ""
            preferred = str((persona or {}).get("preferred_backend") or "").strip().lower()
            if preferred in PROVIDER_REGISTRY:
                return preferred
    pid = str(project_id or "").strip()
    proj = _project_by_id(pid) if pid else None
    assigned = [str(x).strip() for x in (proj or {}).get("assigned_personas", []) if str(x).strip()]
    if persona_id and persona_id in assigned:
        persona = _persona_by_id(persona_id)
        if _persona_is_orchestrator_only(persona):
            return ""
        preferred = str((persona or {}).get("preferred_backend") or "").strip().lower()
        if preferred in PROVIDER_REGISTRY:
            return preferred
    preferreds = []
    for assigned_persona in assigned:
        persona = _persona_by_id(assigned_persona)
        if _persona_is_orchestrator_only(persona):
            continue
        preferred = str((persona or {}).get("preferred_backend") or "").strip().lower()
        if preferred in PROVIDER_REGISTRY:
            preferreds.append(preferred)
    unique = sorted(set(preferreds))
    if len(unique) == 1:
        return unique[0]
    return ""



def _score_adjusted_route(preferred: str, message: str = "") -> tuple:
    """v0.30.38 — Adjust routing based on dispatch quality scores.

    If the preferred backend's recent avg score is significantly lower than
    an alternative (>15 points), route to the higher-scoring backend instead.
    Only activates after 10+ scored dispatches per backend (needs data).
    """
    MIN_DISPATCHES = 10  # Need enough data before overriding
    SCORE_THRESHOLD = 15  # Must beat preferred by this much

    pref_stats = _dispatch_scores_cache.get(preferred)
    if not pref_stats or pref_stats["count"] < MIN_DISPATCHES:
        return _benchmark_adjusted_route(preferred, message)

    pref_avg = pref_stats["avg"]
    best_alt = None
    best_alt_avg = pref_avg

    prefs = _config.get("preferences", {})
    chain = prefs.get("fallback_chain", _DEFAULT_FALLBACK_CHAIN)
    for alt_backend in chain:
        if alt_backend == preferred:
            continue
        alt_stats = _dispatch_scores_cache.get(alt_backend)
        if not alt_stats or alt_stats["count"] < MIN_DISPATCHES:
            continue
        if alt_stats["avg"] > best_alt_avg + SCORE_THRESHOLD:
            if _probe_provider(alt_backend) and not _backend_is_circuit_open(alt_backend):
                best_alt = alt_backend
                best_alt_avg = alt_stats["avg"]

    if best_alt:
        mlog.emit("info", "routing", "route.score_override",
            f"Score override: {preferred} (avg {pref_avg}) → {best_alt} (avg {best_alt_avg})",
            preferred=preferred, override=best_alt)
        log.info("Score-based route override: %s (%.1f) → %s (%.1f)",
            preferred, pref_avg, best_alt, best_alt_avg)
        return (best_alt, None)

    return _benchmark_adjusted_route(preferred, message)


def _smart_route(message, project_id="", task_id="", persona_id=""):
    """Decide which backend to use based on message content.
    Returns (backend, model) tuple. Probes health + walks fallback chain.
    """
    project_hint = _project_route_hint(project_id=project_id, task_id=task_id, persona_id=persona_id)
    if project_hint:
        return _benchmark_adjusted_route(project_hint, message)
    # If routing_mode is "ranked", use user-configured rankings
    prefs = _config.get("preferences", {})
    if prefs.get("routing_mode") == "ranked":
        ranked = _ranked_route()
        if ranked:
            preferred = ranked[0]
            return _benchmark_adjusted_route(preferred, message)
    msg = message.lower().strip()

    # Code-related keywords → OpenClaw (Codex is best at code)
    import re as _re
    code_patterns = [r'\bdef ', r'\bfunction ', r'\bclass ', r'\bimport ', r'\bconst ',
                     r'\breturn ', r'\bif\s*\(', r'\bfor\s*\(', r'```', r'error:',
                     r'\btraceback', r'\bfix\b', r'\bbug\b', r'\bimplement',
                     r'\brefactor', r'\bdebug', r'\bcode\b',
                     r'\.py\b', r'\.js\b', r'\.ts\b', r'\.html\b', r'\.css\b', r'\.json\b',
                     r'\bapi\b', r'\bendpoint\b', r'\bdatabase\b', r'\bquery\b', r'\bsql\b']
    if any(_re.search(p, msg) for p in code_patterns):
        return _score_adjusted_route("codex", message)

    # Quick factual / research → Gemini (fast, good at factual)
    quick_signals = ['what is', 'who is', 'when did', 'how many', 'define ',
                     'explain ', 'summarize', 'translate', 'list ', 'compare']
    if any(msg.startswith(s) or (' ' + s) in msg for s in quick_signals):
        return _score_adjusted_route("gemini", message)

    # Short messages (< 20 chars) → Gemini (fast responses)
    if len(msg) < 20:
        return _score_adjusted_route("gemini", message)

    # Default → Codex CLI (primary chat model), adjusted by dispatch scores
    return _score_adjusted_route("codex", message)


# ── Persona Layer ──────────────────────────────────────────────────────────

def _persona_by_id(persona_id):
    """Fetch persona row from SQLite by ID."""
    try:
        conn = _db_conn()
        row = conn.execute("SELECT * FROM personas WHERE id=?", (persona_id,)).fetchone()
        conn.close()
        return dict(row) if row else None
    except Exception as e:
        log.debug("_persona_by_id error: %s", e)
        return None

def _persona_list(public_only: bool = False):
    """List personas from SQLite."""
    try:
        conn = _db_conn()
        if public_only:
            rows = conn.execute("SELECT * FROM personas WHERE coalesce(is_public,1)=1 ORDER BY sort_order, created_at").fetchall()
        else:
            rows = conn.execute("SELECT * FROM personas ORDER BY sort_order, created_at").fetchall()
        conn.close()
        return [dict(r) for r in rows]
    except Exception as e:
        log.debug("_persona_list error: %s", e)
        return []


def _squad_list(public_only: bool = False):
    """Return all squads with member counts."""
    try:
        conn = _db_conn()
        squads = conn.execute(
            "SELECT s.id, s.name, s.description, s.dispatch_policy, s.color, s.active, "
            "COUNT(sm.persona_id) as member_count, s.project_id "
            "FROM squads s LEFT JOIN squad_members sm ON s.id = sm.squad_id "
            "GROUP BY s.id ORDER BY s.name"
        ).fetchall()
        result = []
        for s in squads:
            members = conn.execute(
                "SELECT p.id, p.name, p.avatar, p.role, p.status, sm.role as squad_role, coalesce(p.is_public,1) as is_public "
                "FROM squad_members sm JOIN personas p ON sm.persona_id = p.id "
                "WHERE sm.squad_id=? ORDER BY sm.position", (s[0],)
            ).fetchall()
            member_rows = []
            for m in members:
                if public_only and not bool(int(m[6] or 0)):
                    continue
                member_rows.append({"id": m[0], "name": m[1], "avatar": m[2], "role": m[3],
                             "status": m[4], "squad_role": m[5]})
            if public_only and not member_rows:
                continue
            result.append({
                "id": s[0], "name": s[1], "description": s[2] or "",
                "dispatch_policy": s[3], "color": s[4], "active": bool(s[5]),
                "member_count": s[6], "project_id": s[7] or "",
                "members": member_rows
            })
        conn.close()
        return result
    except Exception as e:
        log.error("_squad_list failed: %s", e)
        return []

def _squad_by_id(squad_id):
    """Return single squad with members."""
    squads = _squad_list()
    for s in squads:
        if s["id"] == squad_id:
            return s
    return None


def _persona_create(data):
    """Create a new persona, writing DB row + filesystem."""
    import hashlib
    pid = data.get("id") or secrets.token_hex(8)
    name = data.get("name", "New Worker")
    role = data.get("role", "")
    avatar = data.get("avatar", "🤖")
    preferred_backend = data.get("preferred_backend", "")
    fallback_backends = json.dumps(data.get("fallback_backends", []))
    config_json = json.dumps(data.get("config", {}))
    is_system = 1 if data.get("is_system") else 0
    is_public = 0 if data.get("is_public") is False else 1
    is_locked = 1 if data.get("is_locked") else 0
    is_master = 1 if data.get("is_master") else 0
    orchestrator_only = 1 if data.get("orchestrator_only") else 0
    is_temporary = 1 if data.get("is_temporary") else 0
    managed_by_porter = 0 if data.get("managed_by_porter") is False else 1
    appearance_style = str(data.get("appearance_style", "") or "")
    appearance_spec_obj = data.get("appearance_spec", {}) or {}
    if appearance_style == "minecraft" and not appearance_spec_obj:
        appearance_spec_obj = _default_appearance_spec(name, role, bool(is_temporary))
    appearance_spec = json.dumps(appearance_spec_obj)
    from datetime import datetime, timezone as _tz
    now_iso = datetime.now(_tz.utc).isoformat()

    # Build SOUL.md from wizard answers or raw text
    soul_text = data.get("soul_text", "")
    if not soul_text:
        personality = data.get("personality", "")
        focus = data.get("focus", "")
        style = data.get("style", "")
        soul_text = f"# {name}\n\n"
        if role: soul_text += f"**Role:** {role}\n\n"
        if personality: soul_text += f"**Personality:** {personality}\n\n"
        if focus: soul_text += f"**Focus:** {focus}\n\n"
        if style: soul_text += f"**Communication style:** {style}\n\n"

    soul_hash = hashlib.sha256(soul_text.encode()).hexdigest()[:16]

    try:
        conn = _db_conn()
        conn.execute(
            """INSERT INTO personas (id, name, role, avatar, preferred_backend, fallback_backends, status, soul_hash, created_at, config,
               is_system, is_public, is_locked, is_master, orchestrator_only, is_temporary, managed_by_porter, appearance_style, appearance_spec)
               VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)""",
            (pid, name, role, avatar, preferred_backend, fallback_backends, "idle", soul_hash, now_iso, config_json,
             is_system, is_public, is_locked, is_master, orchestrator_only, is_temporary, managed_by_porter, appearance_style, appearance_spec)
        )
        conn.commit()
        conn.close()
    except Exception as e:
        log.error("Failed to create persona: %s", e)
        return None

    # Filesystem — 5-file base pack (ClawOps standard)
    pdir = PERSONAS_DIR / pid
    pdir.mkdir(parents=True, exist_ok=True)
    (pdir / "memory").mkdir(exist_ok=True)

    # 1. SOUL.md — personality, values, style
    (pdir / "SOUL.md").write_text(soul_text)

    # 2. IDENTITY.md — who this agent is
    identity_text = f"# {name}\n\n"
    identity_text += f"**Role:** {role}\n" if role else ""
    identity_text += f"**Avatar:** {avatar}\n" if avatar else ""
    identity_text += f"**Backend:** {preferred_backend}\n" if preferred_backend else ""
    identity_text += f"\n**Created:** {now_iso}\n"
    if not (pdir / "IDENTITY.md").exists():
        (pdir / "IDENTITY.md").write_text(identity_text)

    # 3. MEMORY.md — long-term learned patterns
    if not (pdir / "MEMORY.md").exists():
        (pdir / "MEMORY.md").write_text(
            f"# {name} — Memory\n\n"
            f"Durable rules and learned patterns for {name}.\n\n"
            "## Hard Rules\n\n## Learned Patterns\n\n## Context\n"
        )

    # 4. USER.md — operator preferences
    if not (pdir / "USER.md").exists():
        _op_name = _config.get("display_name", "") or _config.get("username", "Operator")
        _op_tz = _config.get("preferences", {}).get("timezone", "UTC")
        (pdir / "USER.md").write_text(
            f"# User Context for {name}\n\n"
            f"**Human:** {_op_name}\n"
            f"**Timezone:** {_op_tz}\n"
            "**Style:** Direct, practical\n"
        )

    # 5. ROLE_CARD.md — mission, inputs, outputs, authority
    if not (pdir / "ROLE_CARD.md").exists():
        (pdir / "ROLE_CARD.md").write_text(
            f"# {name} — Role Card\n\n"
            f"**Mission:** {role or 'General assistant'}\n\n"
            "## Inputs\n\n- Shared docs from project 00_SHARED/\n\n"
            "## Outputs\n\n- Role-specific deliverables\n- Learning flush updates\n\n"
            "## Authority\n\n- Can flag quality/risk concerns\n"
        )

    # Legacy compatibility
    (pdir / "heartbeat.md").write_text("")

    if not is_locked:
        try:
            persona = {
                "id": pid,
                "name": name,
                "role": role,
                "agent_group": data.get("agent_group", ""),
                "managed_by_porter": managed_by_porter,
            }
            recommended = _recommended_skill_names_for_persona(persona)
            if recommended:
                _persona_set_skill_names(pid, recommended, managed_by_porter=True)
                managed_by_porter = 1
        except Exception as e:
            log.warning("Could not auto-assign starter skills for %s: %s", pid, e)

    return {"id": pid, "name": name, "role": role, "avatar": avatar,
            "preferred_backend": preferred_backend, "soul_hash": soul_hash,
            "is_public": is_public, "is_locked": is_locked, "orchestrator_only": orchestrator_only,
            "managed_by_porter": managed_by_porter,
            "starter_skills": _persona_get_skill_names(pid)}

def _persona_update(persona_id, data):
    """Update persona DB row + optionally SOUL.md."""
    import hashlib
    current = _persona_by_id(persona_id)
    if not current:
        return False
    if _persona_is_locked(current):
        mutable = {"status", "last_active"}
        if any(k not in mutable for k in data.keys()):
            log.warning("Blocked update to locked persona %s", persona_id)
            return False
    sets, vals = [], []
    for field in ("name", "role", "avatar", "preferred_backend", "status", "heartbeat_cron", "hook_profile", "agent_group", "dispatch_mode",
                  "is_public", "is_locked", "is_master", "orchestrator_only", "is_temporary", "managed_by_porter", "appearance_style",
                  "skin_asset_path", "portrait_asset_path"):
        if field in data:
            sets.append(f"{field}=?")
            vals.append(data[field])
    if "heartbeat_enabled" in data:
        sets.append("heartbeat_enabled=?")
        vals.append(1 if data["heartbeat_enabled"] else 0)
    if "fallback_backends" in data:
        sets.append("fallback_backends=?")
        vals.append(json.dumps(data["fallback_backends"]))
    if "config" in data:
        sets.append("config=?")
        vals.append(json.dumps(data["config"]))
    if "appearance_spec" in data:
        sets.append("appearance_spec=?")
        vals.append(json.dumps(data["appearance_spec"]))
    # SOUL.md update
    soul_text = data.get("soul_text")
    if soul_text is not None:
        soul_hash = hashlib.sha256(soul_text.encode()).hexdigest()[:16]
        sets.append("soul_hash=?")
        vals.append(soul_hash)
        soul_path = PERSONAS_DIR / persona_id / "SOUL.md"
        if soul_path.parent.exists():
            soul_path.write_text(soul_text)
    if not sets:
        return False
    vals.append(persona_id)
    try:
        conn = _db_conn()
        conn.execute(f"UPDATE personas SET {', '.join(sets)} WHERE id=?", vals)
        conn.commit()
        conn.close()
        return True
    except Exception as e:
        log.error("Failed to update persona %s: %s", persona_id, e)
        return False

def _persona_delete(persona_id):
    """Delete persona from DB + filesystem."""
    import shutil
    current = _persona_by_id(persona_id)
    if _persona_is_locked(current):
        log.warning("Blocked delete of locked persona %s", persona_id)
        return False
    try:
        conn = _db_conn()
        conn.execute("DELETE FROM personas WHERE id=?", (persona_id,))
        conn.commit()
        conn.close()
    except Exception as e:
        log.error("Failed to delete persona %s: %s", persona_id, e)
        return False
    pdir = PERSONAS_DIR / persona_id
    if pdir.exists():
        shutil.rmtree(pdir, ignore_errors=True)
    return True

def _persona_get_soul(persona_id):
    """Read SOUL.md for a persona."""
    soul_path = PERSONAS_DIR / persona_id / "SOUL.md"
    if soul_path.exists():
        return soul_path.read_text()
    return ""


def _persona_update_soul(persona_id, instruction):
    """Append a shaping instruction to a persona's SOUL.md."""
    if _persona_is_locked(_persona_by_id(persona_id)):
        log.warning("Blocked soul update for locked persona %s", persona_id)
        return
    soul_path = PERSONAS_DIR / persona_id / "SOUL.md"
    soul_path.parent.mkdir(parents=True, exist_ok=True)
    existing = soul_path.read_text().strip() if soul_path.exists() else ""
    from datetime import datetime, timezone as _tz
    ts = datetime.now(_tz.utc).strftime("%Y-%m-%d")
    entry = f"- {instruction.strip()}"
    # Add under a "## Learned Traits" section, create if missing
    if "## Learned Traits" in existing:
        updated = existing + "\n" + entry
    else:
        _dn = _config.get("display_name", "") or _config.get("username", "the operator")
        updated = existing + f"\n\n## Learned Traits\n_Shaped through conversation with {_dn}._\n\n{entry}"
    soul_path.write_text(updated + "\n")
    # Update soul_hash in DB
    import hashlib
    try:
        h = hashlib.sha256(updated.encode()).hexdigest()[:16]
        conn = _db_conn()
        conn.execute("UPDATE personas SET soul_hash=? WHERE id=?", (h, persona_id))
        conn.commit()
        conn.close()
    except Exception:
        pass
    log.info("SOUL.md updated for persona %s: %s", persona_id, instruction[:80])


def _persona_get_rules():
    """Read global RULES.md."""
    rules_path = PERSONAS_DIR / "RULES.md"
    if rules_path.exists():
        return rules_path.read_text()
    return ""

# v0.28.4 — Rules epoch tracking
_rules_epoch = 0
_rules_agent_sync = {}  # agent_id -> epoch_when_last_synced

def _rules_get_epoch():
    """Get current rules epoch."""
    return _rules_epoch

def _rules_bump_epoch():
    """Increment rules epoch when rules change."""
    global _rules_epoch
    _rules_epoch += 1
    mlog.emit("info", "rules", "rules.epoch", f"Rules epoch bumped to {_rules_epoch}")
    return _rules_epoch

def _rules_record_sync(agent_id):
    """Record that an agent has synced with current rules epoch."""
    _rules_agent_sync[agent_id] = _rules_epoch

def _rules_stale_agents():
    """Return list of agents that haven't synced with current rules."""
    stale = []
    try:
        conn = _db_conn()
        agents = conn.execute("SELECT id, name FROM personas").fetchall()
        conn.close()
        for a in agents:
            synced_epoch = _rules_agent_sync.get(a[0], 0)
            if synced_epoch < _rules_epoch:
                stale.append({"id": a[0], "name": a[1], "synced_epoch": synced_epoch, "current_epoch": _rules_epoch})
    except Exception:
        pass
    return stale

def _persona_set_rules(text):
    """Write global RULES.md and bump epoch."""
    rules_path = PERSONAS_DIR / "RULES.md"
    PERSONAS_DIR.mkdir(parents=True, exist_ok=True)
    rules_path.write_text(text)
    _rules_bump_epoch()
    return True

def _persona_get_memory(persona_id):
    """Get persona's MEMORY.md + daily logs."""
    pdir = PERSONAS_DIR / persona_id
    result = {"memory_md": "", "daily_logs": []}
    mem_path = pdir / "MEMORY.md"
    if mem_path.exists():
        result["memory_md"] = mem_path.read_text()
    log_dir = pdir / "memory"
    if log_dir.exists():
        for f in sorted(log_dir.glob("*.md"), reverse=True)[:30]:
            result["daily_logs"].append({"date": f.stem, "content": f.read_text()[:5000]})
    return result

def _persona_append_daily_log(persona_id, text):
    """Append text to today's daily log for a persona."""
    from datetime import datetime, timezone as _tz
    today = datetime.now(_tz.utc).strftime("%Y-%m-%d")
    log_dir = PERSONAS_DIR / persona_id / "memory"
    log_dir.mkdir(parents=True, exist_ok=True)
    log_path = log_dir / f"{today}.md"
    existing = log_path.read_text() if log_path.exists() else ""
    from datetime import datetime as _dt2
    timestamp = _dt2.now(_tz.utc).strftime("%H:%M:%S UTC")
    log_path.write_text(existing + f"\n## {timestamp}\n\n{text}\n")


# v0.29.27 — Verification Loop: post-dispatch quality check for strict agents
def _verify_dispatch_response(original_message, response_text, agent_name="", backend="", run_id="", persona_id=""):
    """Quick verification of dispatch response quality. Returns {passed, score, reason}."""
    import time as _vt
    _v_t0 = _vt.time()
    issues = []
    score = 100

    # Check 1: Response not empty or too short
    if not response_text or len(response_text.strip()) < 10:
        issues.append("Response too short or empty")
        score -= 40

    # Check 2: Response not just echoing the question
    if response_text.strip().lower()[:100] == original_message.strip().lower()[:100]:
        issues.append("Response appears to echo the input")
        score -= 30

    # Check 3: No obvious error/hedging patterns
    _error_patterns = ["i can't", "i cannot", "i'm unable", "as an ai", "i don't have access",
                       "error occurred", "something went wrong", "i apologize, but i"]
    _resp_lower = response_text.lower()
    for ep in _error_patterns:
        if ep in _resp_lower:
            issues.append(f"Response contains hedging: '{ep}'")
            score -= 10
            break

    # Check 4: Response relevance — keyword overlap
    import re as _vre
    q_words = set(_vre.findall(r'[a-zA-Z]{4,}', original_message.lower()))
    r_words = set(_vre.findall(r'[a-zA-Z]{4,}', response_text.lower()))
    overlap = q_words & r_words
    if len(q_words) > 3 and len(overlap) < 1:
        issues.append("Low keyword overlap with question")
        score -= 15

    passed = score >= 60
    reason = "; ".join(issues) if issues else "OK"
    _v_dur = round(_vt.time() - _v_t0, 4)

    # Log to trace
    try:
        emit_trace_step("verification",
            agent_id=persona_id, agent_name=agent_name,
            stage="verify", input_summary=f"score={score}, passed={passed}",
            status="done" if passed else "error",
            trace_id=run_id)
    except Exception:
        pass

    return {"passed": passed, "score": score, "reason": reason, "duration_s": _v_dur}



# ── Dispatch Result Scoring (v0.30.37) ───────────────────────────────────

def _score_dispatch_result(result: dict, latency_ms: int, backend: str,
                           verification: dict = None) -> int:
    """v0.30.37 — Heuristic quality score (0-100) for a dispatch result.

    Scoring breakdown:
    - Base: 0 (failure) or 50 (success)
    - Response substance: +0-20 based on length (100→5, 500→15, 1000+→20)
    - Speed: +0-15 based on latency (<2s→15, <5s→10, <10s→5, >10s→0)
    - Clean dispatch: +10 if no retries/fallback needed
    - Verification: +5 if passed (strict agents only)
    """
    if not result.get("ok"):
        return 0
    score = 50  # Base for successful dispatch
    # Response substance
    text = result.get("text", "") or ""
    text_len = len(text.strip())
    if text_len >= 1000:
        score += 20
    elif text_len >= 500:
        score += 15
    elif text_len >= 100:
        score += 5
    # Speed bonus
    if latency_ms < 2000:
        score += 15
    elif latency_ms < 5000:
        score += 10
    elif latency_ms < 10000:
        score += 5
    # Clean dispatch (no fallback marker in result)
    if not result.get("fallback_used"):
        score += 10
    # Verification bonus
    if verification and verification.get("passed"):
        score += 5
    return min(score, 100)


# ── Backend Performance Aggregation (v0.30.37) ──────────────────────────

_dispatch_scores_cache = {}  # backend → {total_score, count, avg, last_updated}

def _update_dispatch_score_cache(backend: str, score: int):
    """Track rolling average score per backend."""
    if backend not in _dispatch_scores_cache:
        _dispatch_scores_cache[backend] = {"total_score": 0, "count": 0, "avg": 0.0, "last_updated": 0}
    entry = _dispatch_scores_cache[backend]
    entry["total_score"] += score
    entry["count"] += 1
    entry["avg"] = round(entry["total_score"] / entry["count"], 1)
    import time as _dsc_t
    entry["last_updated"] = _dsc_t.time()


def dispatch_to_persona(message, persona_id, timeout=120, run_id=None, chain_id=None, step_num=0,
                        personality_mode=False, backend_override="", project_id="", task_id=""):
    """Dispatch a message to a persona: load SOUL, resolve backend, call dispatch_agent."""
    import uuid as _uuid
    import time as _ptime
    if not run_id:
        run_id = _uuid.uuid4().hex[:12]

    persona = _persona_by_id(persona_id)
    if not persona:
        return {"ok": False, "error": f"Persona not found: {persona_id}", "run_id": run_id}
    if _persona_is_orchestrator_only(persona):
        return {"ok": False, "error": f"{persona.get('name', 'This persona')} is orchestrator-only and cannot execute worker tasks.", "run_id": run_id}

    # v0.28.4 — Loop guard check (agent dispatch = not human)
    _lg_chat_id = chain_id or run_id or ""
    if _lg_chat_id:
        _lg_ok, _lg_msg = _loop_guard_check(_lg_chat_id, sender_is_human=False)
        if not _lg_ok:
            log.warning("Loop guard blocked dispatch to %s: %s", persona.get("name", "?"), _lg_msg)
            return {"ok": False, "error": _lg_msg, "run_id": run_id, "loop_guard": True}

    # Load all persona .md files + global RULES.md for dispatch context
    # Safety cap per file: 20KB (prevents accidental mega-files from blowing context)
    _CTX_FILE_CAP = 20_000
    def _read_persona_file(path):
        try:
            if path.exists():
                content = path.read_text().strip()
                return content[:_CTX_FILE_CAP] if content else ''
        except Exception:
            pass
        return ''

    pdir = PERSONAS_DIR / persona_id
    soul = _read_persona_file(pdir / 'SOUL.md')
    # v0.28.4 — Record that this agent has synced with current rules
    _rules_record_sync(persona_id)

    pname = persona.get('name', 'Agent')
    prole = persona.get('role', '')
    resolved_project_id = _resolve_persona_project(persona_id, explicit_project_id=project_id, task_id=task_id)
    task = _task_by_id(task_id)

    # v0.28.9 — Budgeted context suffix (replaces uncapped assembly)
    _ctx_suffix = _build_context_suffix(persona_id, message=message, project_id=resolved_project_id, task_id=task_id)

    # v0.28.9 — History trimmer: keep last 3 turns, cap at 3000 chars
    _MAX_HISTORY_CHARS = 3000
    if len(message) > _MAX_HISTORY_CHARS:
        _hist_marker = "Conversation history:"
        if _hist_marker in message:
            _hist_start = message.index(_hist_marker)
            _after_hist = message[_hist_start:]
            _new_msg_marker = "\nNew message:\n"
            if _new_msg_marker in _after_hist:
                _nm_pos = _after_hist.index(_new_msg_marker)
                _history_block = _after_hist[:_nm_pos]
                _new_msg_block = _after_hist[_nm_pos:]
                _turns = _history_block.split("\nUser:")
                if len(_turns) > 3:
                    _trimmed_hist = _hist_marker + "\n(earlier turns trimmed)\n\nUser:" + "\nUser:".join(_turns[-3:])
                    message = _trimmed_hist + _new_msg_block
                    log.info("Persona dispatch: trimmed conversation from %d to %d chars", len(message) + len(_history_block), len(message))
            else:
                message = message[-_MAX_HISTORY_CHARS:]
        else:
            message = message[-_MAX_HISTORY_CHARS:]

    # Personality mode: conversational, includes identity context
    if personality_mode:
        _role_line = f"Role: {prole}\n" if prole else ""
        # v0.29.43 — Squad leader context: inject roster of squad members
        _squad_ctx = ""
        try:
            _all_squads = _squad_list()
            for _sq in _all_squads:
                _is_leader = any(m["id"] == persona_id and m.get("squad_role") == "leader" for m in _sq.get("members", []))
                if _is_leader:
                    _roster_lines = []
                    for _sm in _sq["members"]:
                        if _sm["id"] == persona_id:
                            continue
                        _sk_data = []
                        try:
                            _sk_conn = _db_conn()
                            _sk_rows = _sk_conn.execute("SELECT skill_name FROM persona_skills WHERE persona_id=? AND enabled=1", (_sm["id"],)).fetchall()
                            _sk_conn.close()
                            _sk_data = [r[0] for r in _sk_rows]
                        except Exception:
                            pass
                        _sk_str = ", ".join(_sk_data) if _sk_data else "none"
                        _roster_lines.append(f"- {_sm.get('avatar','')} {_sm['name']} ({_sm.get('role','agent')}): skills=[{_sk_str}]")
                    if _roster_lines:
                        _squad_ctx += f"\nYou are the LEADER of {_sq['name']}.\nYour squad members:\n" + "\n".join(_roster_lines)
                        if _sq.get("description"):
                            _squad_ctx += f"\nSquad mission: {_sq['description']}"
        except Exception:
            pass
        _system_block = (
            f"=== SYSTEM PROMPT ===\n"
            f"You are {pname}.\n"
            f"{_role_line}"
            + (_squad_ctx + "\n" if _squad_ctx else "")
            + f"Voice: first person, conversational, direct.\n"
            f"Format: short paragraphs, markdown when useful, front-load the answer.\n"
            f"Rule: Never mention which AI model or backend you run on.\n"
            f"Rule: If the user changes a preference that contradicts your persona files, flag it and ask whether to update your memory.\n"
            f"=== END SYSTEM PROMPT ==="
        )
        augmented_message = f"{message}\n\n{_system_block}\n\n{_ctx_suffix}"
    elif _ctx_suffix:
        _system_block = (
            f"=== SYSTEM PROMPT ===\n"
            f"You are {pname}.\n"
            f"Format: front-load the answer, short paragraphs, markdown for structure.\n"
            f"Rule: Never mention which AI model you run on.\n"
            f"=== END SYSTEM PROMPT ==="
        )
        augmented_message = f"{message}\n\n{_system_block}\n\n{_ctx_suffix}"
    else:
        augmented_message = message

    # If user asks about identity/soul, include full SOUL.md in the message
    _msg_lower = message.lower()
    _identity_triggers = ['soul.md', 'your soul', 'your identity', 'about yourself', 'who are you',
                          'tell me about you', 'describe yourself', 'your personality', 'your role',
                          'what are you', 'show me your', 'your files']
    if any(t in _msg_lower for t in _identity_triggers) and soul.strip():
        augmented_message = f"{message}\n\n--- Your SOUL.md file ---\n{soul.strip()}\n--- End SOUL.md ---\n\n(Respond as {pname} in first person. ONLY use information from the SOUL.md above. Do not invent details about your backend, model, squad, or project assignments. Never mention which AI model you run on. If something is not in your SOUL.md, do not mention it.)"

    # Resolve backend
    _be_override = backend_override
    backend = _be_override if _be_override and _be_override in PROVIDER_REGISTRY else persona.get("preferred_backend", "").strip()
    model_override = None
    if not backend or backend not in PROVIDER_REGISTRY:
        # Try fallback chain
        try:
            fallbacks = json.loads(persona.get("fallback_backends", "[]"))
        except Exception:
            fallbacks = []
        for fb in fallbacks:
            if fb in PROVIDER_REGISTRY:
                backend = fb
                break
        if not backend or backend not in PROVIDER_REGISTRY:
            # Smart route as last resort
            backend, model_override = _smart_route(message, project_id=resolved_project_id, task_id=task_id, persona_id=persona_id)

    # Update persona status
    try:
        conn = _db_conn()
        conn.execute("UPDATE personas SET status='active', last_active=strftime('%s','now') WHERE id=?", (persona_id,))
        conn.commit()
        conn.close()
    except Exception:
        pass

    if task:
        _task_to_save = None
        with _treg_lock:
            live_task = _treg.get(str(task.get("id") or task_id).strip())
            if live_task:
                live_task["assigned_persona_id"] = persona_id
                if resolved_project_id and not live_task.get("project_id"):
                    live_task["project_id"] = resolved_project_id
                if live_task.get("status") == "pending":
                    live_task["status"] = "in_progress"
                live_task["updated_at"] = _ptime.time()
                _task_to_save = dict(live_task)
        if _task_to_save:
            _treg_save(_task_to_save)

    log.info("Persona dispatch: %s (%s) → %s", persona.get("name", "?"), persona_id, backend)
    mlog.emit("info", "bridge", "persona.dispatch", f"Persona {persona.get('name', '?')} → {backend}", persona_id=persona_id, backend=backend, run_id=run_id)

    # Trace: dispatch start
    emit_trace_step("persona.dispatch",
        agent_id=persona_id, agent_name=persona.get("name", "?"),
        stage="dispatch", input_summary=message[:200], status="running",
        project_id=resolved_project_id or None, task_id=str(task_id or "").strip() or None,
        trace_id=_get_trace_id())

    _dtp_t0 = _ptime.time()
    # Dispatch via existing agent dispatch
    # v0.28.9 — Final augmented prompt cap
    _MAX_AUGMENTED_CHARS = _config.get("preferences", {}).get("hygiene_max_augmented_chars", 8000)
    if len(augmented_message) > _MAX_AUGMENTED_CHARS:
        log.info("Persona dispatch: augmented_message trimmed from %d to %d chars", len(augmented_message), _MAX_AUGMENTED_CHARS)
        augmented_message = augmented_message[:_MAX_AUGMENTED_CHARS]

    result = dispatch_agent(augmented_message, backend, model=model_override, timeout=timeout, run_id=run_id, chain_id=chain_id, step_num=step_num)

    # v0.30.26 — Auto-fallback: if primary failed OR response contains rate-limit text, try fallbacks
    _resp_text = (result.get("text", "") or "").lower()
    _rl_in_text = any(p in _resp_text for p in ["rate limit", "quota exceeded", "too many requests", "try again later", "api rate limit"])
    if _rl_in_text and result.get("ok"):
        result["ok"] = False
        result["error"] = f"Rate limit detected in response text: {result.get('text', '')[:100]}"
        log.warning("Rate limit detected in response text from %s", backend)
    if not result.get("ok"):
        _fail_reason = result.get("error", "")
        _rate_limit_phrases = ["rate limit", "quota exceeded", "too many requests", "429", "timed out",
                               "timeout", "connection refused", "503", "overloaded", "capacity"]
        _should_fallback = any(p in _fail_reason.lower() for p in _rate_limit_phrases) or not _fail_reason
        if _should_fallback:
            try:
                _fb_list = json.loads(persona.get("fallback_backends", "[]"))
            except Exception:
                _fb_list = []
            for _fb_backend in _fb_list:
                if _fb_backend == backend or _fb_backend not in PROVIDER_REGISTRY:
                    continue
                log.warning("Auto-fallback: %s failed (%s), trying %s", backend, _fail_reason[:80], _fb_backend)
                mlog.emit("warn", "bridge", "persona.fallback",
                    f"{persona.get('name','?')}: {backend} failed, falling back to {_fb_backend}",
                    persona_id=persona_id, backend=_fb_backend, run_id=run_id)
                _emit_event("persona:fallback", {"persona_id": persona_id, "from": backend, "to": _fb_backend, "reason": _fail_reason[:100]})
                result = dispatch_agent(augmented_message, _fb_backend, timeout=timeout, run_id=run_id, chain_id=chain_id, step_num=step_num)
                if result.get("ok"):
                    backend = _fb_backend  # Update for logging
                    break
                log.warning("Auto-fallback: %s also failed: %s", _fb_backend, result.get("error", "?")[:80])

    # Tag the agent_message with persona_id
    try:
        conn = _db_conn()
        conn.execute(
            "UPDATE agent_messages SET persona_id=?, project_id=?, task_id=? WHERE run_id=?",
            (persona_id, resolved_project_id or None, str(task_id or "").strip() or None, run_id)
        )
        conn.commit()
        conn.close()
    except Exception:
        pass

    # Append to daily log
    response_text = result.get("text", "")[:500] if result.get("ok") else result.get("error", "")[:200]
    _persona_append_daily_log(persona_id, f"**Dispatch** ({backend})\n> {message[:200]}\n\nResponse: {response_text}")

    # v0.29.27 — Verification Loop for strict hook profile agents
    _hook_profile = persona.get("hook_profile", "balanced")
    if _hook_profile == "strict" and result.get("ok") and result.get("text"):
        try:
            _verify_result = _verify_dispatch_response(
                original_message=message[:500],
                response_text=result["text"][:1000],
                agent_name=pname,
                backend=backend,
                run_id=run_id,
                persona_id=persona_id,
            )
            result["verification"] = _verify_result
            if not _verify_result.get("passed"):
                log.warning("Verification FAILED for %s: %s", pname, _verify_result.get("reason", ""))
                mlog.emit("warn", "bridge", "verification.failed",
                    f"{pname}: {_verify_result.get('reason','')}", persona_id=persona_id, run_id=run_id)
        except Exception as _ve:
            log.debug("Verification skipped: %s", _ve)

    # Soul shaping: detect identity instructions and persist to SOUL.md
    _shaping_triggers = ['remember that you', 'from now on you', 'you should always',
                         'you should never', 'your personality is', 'your tone should',
                         'start being more', 'stop being so', 'be more', 'be less',
                         'you are now', 'i want you to be', 'change your', 'update your personality',
                         'update your soul', 'add to your soul', 'your new trait',
                         'always remember', 'never forget that you']
    if any(t in _msg_lower for t in _shaping_triggers) and result.get("ok"):
        # Extract the instruction (use the raw message, not augmented)
        _persona_update_soul(persona_id, message.strip())
        _persona_append_daily_log(persona_id, f"**Soul shaped**: {message[:200]}")

    # Trace + Telemetry: dispatch complete
    _dtp_dur = int((_ptime.time() - _dtp_t0) * 1000)
    _dtp_ok = result.get("ok", False)
    _dtp_tokens = result.get("tokens_total", 0)
    emit_trace_step("persona.complete",
        agent_id=persona_id, agent_name=persona.get("name", "?"),
        stage="complete", output_summary=(result.get("text", "") or "")[:200],
        status="complete" if _dtp_ok else "failed",
        duration_ms=_dtp_dur, tokens_out=_dtp_tokens,
        project_id=resolved_project_id or None, task_id=str(task_id or "").strip() or None,
        trace_id=_get_trace_id())
    record_telemetry(
        project_id=resolved_project_id or None,
        agent_id=persona_id, agent_name=persona.get("name", "?"),
        status="complete" if _dtp_ok else "failed",
        tokens_out=_dtp_tokens, latency_ms=_dtp_dur,
        backend=backend, action="dispatch_to_persona",
        run_id=run_id, trace_id=_get_trace_id())

    # v0.30.37 — Dispatch result scoring
    _dtp_score = _score_dispatch_result(result, _dtp_dur, backend,
                                         verification=result.get("verification"))
    result["quality_score"] = _dtp_score
    _update_dispatch_score_cache(backend, _dtp_score)
    # Persist score + backend to agent_messages
    try:
        _sc_conn = _db_conn()
        _sc_conn.execute("UPDATE agent_messages SET quality_score=?, backend=? WHERE run_id=?",
                         (_dtp_score, backend, run_id))
        _sc_conn.commit()
        _sc_conn.close()
    except Exception:
        pass

    # Reset status to idle
    try:
        conn = _db_conn()
        conn.execute("UPDATE personas SET status='idle' WHERE id=?", (persona_id,))
        conn.commit()
        conn.close()
    except Exception:
        pass

    # v0.28.4 — Detect job proposals in agent response
    if result.get("ok") and result.get("text"):
        _resp_text = result.get("text", "")
        if "[proposal]" in _resp_text.lower() or "[suggest]" in _resp_text.lower():
            # Parse proposal: first line after tag is title, rest is body
            import re as _re_prop
            _prop_match = _re_prop.search(r'\[(?:proposal|suggest)\]\s*(.+?)(?:\n|$)', _resp_text, _re_prop.IGNORECASE)
            if _prop_match:
                _prop_title = _prop_match.group(1).strip()[:200]
                _prop_body = _resp_text[_prop_match.end():].strip()[:2000]
                try:
                    conn_prop = _db_conn()
                    conn_prop.execute(
                        "INSERT INTO job_proposals (title, body, proposed_by, proposed_by_name) VALUES (?, ?, ?, ?)",
                        (_prop_title, _prop_body, persona_id, pname))
                    conn_prop.commit()
                    conn_prop.close()
                    _emit_event("job:proposal", {"title": _prop_title, "agent": pname, "persona_id": persona_id})
                    mlog.emit("info", "jobs", "job.proposal", f"Agent {pname} proposed: {_prop_title}", persona_id=persona_id)
                except Exception as _pe:
                    log.debug("Job proposal insert failed: %s", _pe)

    # Legacy extractive memory is disabled by default in Memory V3.
    if _memory_auto_extract_enabled() and result.get("ok") and result.get("text"):
        _cortex_msg = message
        _cortex_resp = result.get("text", "")
        _cortex_pid = persona_id
        _cortex_be = backend
        _cortex_project = resolved_project_id
        _cortex_task = str(task_id or "").strip()
        def _cortex_bg():
            _cortex_extract_and_route(_cortex_msg, _cortex_resp, _cortex_pid, _cortex_be, project_id=_cortex_project, task_id=_cortex_task)
        threading.Thread(target=_cortex_bg, name="cortex-extract", daemon=True).start()

    if task:
        _task_to_save = None
        with _treg_lock:
            live_task = _treg.get(str(task.get("id") or task_id).strip())
            if live_task:
                live_task["status"] = "complete" if result.get("ok") else "failed"
                live_task["result"] = (result.get("text", "") if result.get("ok") else result.get("error", ""))[:2000] or None
                live_task["updated_at"] = _ptime.time()
                if result.get("ok"):
                    live_task["completed_at"] = _ptime.time()
                _task_to_save = dict(live_task)
        if _task_to_save:
            _treg_save(_task_to_save)

    result["persona_id"] = persona_id
    result["project_id"] = resolved_project_id
    result["task_id"] = str(task_id or "").strip()
    return result





# ── Standup Generation (v0.30.44) ────────────────────────────────────────
# Auto-summarize recent dispatch activity per project into a standup report.

def _generate_standup(project_id: str = "", hours: int = 24) -> dict:
    """v0.30.44 — Generate a standup summary for a project (or all projects).

    Returns:
    - dispatches: count of dispatches in the period
    - completions: successful dispatches
    - failures: failed dispatches
    - agents_active: list of agents that dispatched
    - top_tasks: recent completed tasks
    - anomalies: any anomalies detected
    - insights: from pattern mining
    """
    import time as _sut
    cutoff = _sut.time() - (hours * 3600)
    report = {
        "period_hours": hours,
        "project_id": project_id or "all",
        "generated_at": _sut.time(),
        "dispatches": 0,
        "completions": 0,
        "failures": 0,
        "agents_active": [],
        "top_tasks": [],
        "anomalies": [],
        "summary_lines": [],
    }
    try:
        conn = _db_conn()
        # Dispatch stats
        if project_id:
            stats = conn.execute("""
                SELECT COUNT(*) as total,
                       SUM(CASE WHEN status='complete' THEN 1 ELSE 0 END) as ok,
                       SUM(CASE WHEN status='failed' THEN 1 ELSE 0 END) as fail
                FROM agent_messages
                WHERE project_id = ? AND created_at > ?
            """, (project_id, cutoff)).fetchone()
        else:
            stats = conn.execute("""
                SELECT COUNT(*) as total,
                       SUM(CASE WHEN status='complete' THEN 1 ELSE 0 END) as ok,
                       SUM(CASE WHEN status='failed' THEN 1 ELSE 0 END) as fail
                FROM agent_messages
                WHERE created_at > ?
            """, (cutoff,)).fetchone()
        report["dispatches"] = stats[0] or 0
        report["completions"] = stats[1] or 0
        report["failures"] = stats[2] or 0

        # Active agents
        if project_id:
            agents = conn.execute("""
                SELECT DISTINCT p.name FROM agent_messages am
                JOIN personas p ON am.persona_id = p.id
                WHERE am.project_id = ? AND am.created_at > ?
            """, (project_id, cutoff)).fetchall()
        else:
            agents = conn.execute("""
                SELECT DISTINCT p.name FROM agent_messages am
                JOIN personas p ON am.persona_id = p.id
                WHERE am.created_at > ? AND am.persona_id IS NOT NULL
            """, (cutoff,)).fetchall()
        report["agents_active"] = [a[0] for a in agents]

        # Recent completed tasks
        if project_id:
            tasks = conn.execute("""
                SELECT title, status, assigned_persona_id FROM tasks
                WHERE project_id = ? AND updated_at > ?
                ORDER BY updated_at DESC LIMIT 5
            """, (project_id, cutoff)).fetchall()
        else:
            tasks = conn.execute("""
                SELECT title, status, assigned_persona_id FROM tasks
                WHERE updated_at > ?
                ORDER BY updated_at DESC LIMIT 5
            """, (cutoff,)).fetchall()
        report["top_tasks"] = [
            {"title": t[0], "status": t[1], "agent": t[2] or "unassigned"}
            for t in tasks
        ]
        conn.close()
    except Exception as e:
        log.debug("Standup generation error: %s", e)
        report["error"] = str(e)[:200]

    # Build summary lines
    lines = []
    if report["dispatches"] > 0:
        rate = round((report["completions"] / report["dispatches"]) * 100) if report["dispatches"] > 0 else 0
        lines.append(f"{report['dispatches']} dispatches ({rate}% success rate)")
    if report["agents_active"]:
        lines.append(f"Active agents: {', '.join(report['agents_active'][:5])}")
    if report["top_tasks"]:
        done = [t for t in report["top_tasks"] if t["status"] == "complete"]
        if done:
            lines.append(f"Completed: {', '.join(t['title'][:40] for t in done[:3])}")
    if report["failures"] > 0:
        lines.append(f"{report['failures']} failures — check Mission Control")
    if not lines:
        lines.append("No dispatch activity in this period")
    report["summary_lines"] = lines
    return report


# ── Pattern Mining (v0.30.41) ────────────────────────────────────────────
# Analyzes dispatch history to find performance trends and surface insights.
# Runs periodically (every 6h) and stores findings as Cortex project-scoped memories.

_pattern_mining_results = {}  # Last mining results

def _pattern_mining_run():
    """v0.30.41 — Analyze dispatch history from last 7 days for routing insights.

    Produces:
    - Per-agent success rates + avg quality scores
    - Per-backend reliability comparison
    - Common failure patterns (top 5 error messages)
    - Peak performance hours per backend
    """
    import time as _pmt
    results = {"ts": _pmt.time(), "insights": []}
    try:
        conn = _db_conn()
        # 1. Per-agent performance (last 7 days)
        agent_stats = conn.execute("""
            SELECT persona_id, backend,
                   COUNT(*) as total,
                   SUM(CASE WHEN status='complete' THEN 1 ELSE 0 END) as successes,
                   AVG(quality_score) as avg_score,
                   AVG(duration_ms) as avg_latency
            FROM agent_messages
            WHERE created_at > strftime('%s','now') - 604800
              AND persona_id IS NOT NULL AND persona_id != ''
            GROUP BY persona_id, backend
            HAVING total >= 3
            ORDER BY avg_score DESC
        """).fetchall()
        if agent_stats:
            top = []
            for r in agent_stats[:10]:
                rate = round((r[3] / r[2]) * 100) if r[2] > 0 else 0
                top.append({
                    "persona_id": r[0], "backend": r[1],
                    "dispatches": r[2], "success_rate": rate,
                    "avg_score": round(r[4] or 0, 1),
                    "avg_latency_ms": int(r[5] or 0)
                })
            results["agent_performance"] = top
            # Insight: best agent+backend combo
            if top:
                best = top[0]
                results["insights"].append(
                    f"Best performer: persona {best['persona_id']} on {best['backend']} "
                    f"({best['success_rate']}% success, avg score {best['avg_score']})")

        # 2. Per-backend reliability
        backend_stats = conn.execute("""
            SELECT backend,
                   COUNT(*) as total,
                   SUM(CASE WHEN status='complete' THEN 1 ELSE 0 END) as successes,
                   AVG(quality_score) as avg_score,
                   AVG(duration_ms) as avg_latency
            FROM agent_messages
            WHERE created_at > strftime('%s','now') - 604800
              AND backend IS NOT NULL AND backend != ''
            GROUP BY backend
            HAVING total >= 5
            ORDER BY avg_score DESC
        """).fetchall()
        if backend_stats:
            backends = []
            for r in backend_stats:
                rate = round((r[2] / r[1]) * 100) if r[1] > 0 else 0
                backends.append({
                    "backend": r[0], "dispatches": r[1],
                    "success_rate": rate, "avg_score": round(r[3] or 0, 1),
                    "avg_latency_ms": int(r[4] or 0)
                })
            results["backend_reliability"] = backends
            if len(backends) >= 2:
                best_be = backends[0]
                worst_be = backends[-1]
                if best_be["avg_score"] - worst_be["avg_score"] > 10:
                    results["insights"].append(
                        f"Backend gap: {best_be['backend']} (score {best_be['avg_score']}) "
                        f"outperforms {worst_be['backend']} (score {worst_be['avg_score']}) by "
                        f"{round(best_be['avg_score'] - worst_be['avg_score'], 1)} points")

        # 3. Common failure patterns
        failures = conn.execute("""
            SELECT error, COUNT(*) as cnt
            FROM agent_messages
            WHERE status = 'failed'
              AND created_at > strftime('%s','now') - 604800
              AND error IS NOT NULL AND error != ''
            GROUP BY error
            ORDER BY cnt DESC
            LIMIT 5
        """).fetchall()
        if failures:
            results["top_failures"] = [
                {"error": r[0][:120], "count": r[1]} for r in failures
            ]
            if failures[0][1] >= 5:
                results["insights"].append(
                    f"Recurring failure ({failures[0][1]}x): {failures[0][0][:80]}")

        # 4. Hourly performance distribution (find peak hours)
        hourly = conn.execute("""
            SELECT CAST(strftime('%H', datetime(created_at, 'unixepoch', 'localtime')) AS INTEGER) as hour,
                   AVG(quality_score) as avg_score,
                   COUNT(*) as total
            FROM agent_messages
            WHERE created_at > strftime('%s','now') - 604800
              AND quality_score > 0
            GROUP BY hour
            HAVING total >= 3
            ORDER BY avg_score DESC
        """).fetchall()
        if hourly:
            results["hourly_performance"] = [
                {"hour": r[0], "avg_score": round(r[1] or 0, 1), "dispatches": r[2]}
                for r in hourly
            ]
            if len(hourly) >= 2:
                best_h = hourly[0]
                worst_h = hourly[-1]
                results["insights"].append(
                    f"Best hour: {best_h[0]:02d}:00 (score {round(best_h[1],1)}), "
                    f"worst: {worst_h[0]:02d}:00 (score {round(worst_h[1],1)})")

        conn.close()
    except Exception as e:
        log.debug("Pattern mining error: %s", e)
        results["error"] = str(e)[:200]

    global _pattern_mining_results
    _pattern_mining_results = results

    # Log insights to Mission Control
    if results.get("insights"):
        summary = " | ".join(results["insights"][:3])
        mlog.emit("info", "intelligence", "pattern_mining.complete",
            f"Pattern mining: {len(results.get('insights',[]))} insights — {summary}")
        _emit_event("intelligence:patterns", {
            "insights": results["insights"],
            "agent_count": len(results.get("agent_performance", [])),
            "backend_count": len(results.get("backend_reliability", [])),
        })
    return results


# ── Self-Dispatch (v0.30.40) ─────────────────────────────────────────────
# Porter creates internal tasks and dispatches them to agents without human trigger.
# Sources: anomaly alerts, health failures, scheduled analysis, pattern detection.
# Guards: rate limit (max 5 self-dispatches per hour), loop guard, opt-in via preferences.

_self_dispatch_log = []  # Recent self-dispatches: [{ts, task_id, persona_id, reason, status}]
_self_dispatch_lock = threading.Lock()
_SELF_DISPATCH_MAX_PER_HOUR = 5

def _self_dispatch_allowed() -> bool:
    """Check if we can self-dispatch (rate limit + preference check)."""
    prefs = _config.get("preferences", {})
    if not prefs.get("self_dispatch_enabled", False):
        return False
    import time as _sdt
    cutoff = _sdt.time() - 3600
    with _self_dispatch_lock:
        recent = [d for d in _self_dispatch_log if d["ts"] > cutoff]
        _self_dispatch_log[:] = recent
        return len(recent) < _SELF_DISPATCH_MAX_PER_HOUR


def _self_dispatch(persona_id: str, message: str, reason: str,
                   project_id: str = "", priority: str = "normal") -> dict:
    """Create an internal task and dispatch it to an agent.
    Returns dispatch result dict. Rate-limited and logged to Mission Control.
    """
    import time as _sdt2, uuid as _sdu
    if not _self_dispatch_allowed():
        return {"ok": False, "error": "Self-dispatch rate limit reached or disabled"}
    task_id = f"auto-{_sdu.uuid4().hex[:8]}"
    task = {
        "id": task_id,
        "title": f"[Auto] {reason[:80]}",
        "description": message[:500],
        "status": "pending",
        "priority": priority,
        "project_id": project_id,
        "assigned_persona_id": persona_id,
        "created_at": _sdt2.time(),
        "updated_at": _sdt2.time(),
        "tags": json.dumps(["auto-dispatch"]),
        "sort_order": 0,
    }
    _treg_save(task)
    mlog.emit("info", "self_dispatch", "self_dispatch.created",
        f"Auto-task created: {reason[:80]} -> {persona_id}",
        persona_id=persona_id, task_id=task_id)
    log.info("Self-dispatch: %s -> %s (reason: %s)", task_id, persona_id, reason[:80])
    result = dispatch_to_persona(message, persona_id, timeout=120,
                                  project_id=project_id, task_id=task_id)
    entry = {
        "ts": _sdt2.time(),
        "task_id": task_id,
        "persona_id": persona_id,
        "reason": reason[:100],
        "status": "complete" if result.get("ok") else "failed",
    }
    with _self_dispatch_lock:
        _self_dispatch_log.append(entry)
    _emit_event("self_dispatch:complete", {
        "task_id": task_id, "persona_id": persona_id,
        "ok": result.get("ok", False), "reason": reason[:100]
    })
    return result


def _self_dispatch_on_anomaly(anomalies: list):
    """React to detected anomalies by dispatching investigative tasks."""
    if not _self_dispatch_allowed():
        return
    bugbanisher_id = None
    try:
        personas = _persona_list()
        for p in personas:
            if "bugbanisher" in (p.get("name", "") or "").lower().replace(" ", ""):
                bugbanisher_id = p["id"]
                break
    except Exception:
        pass
    for anomaly in anomalies[:2]:
        agent_name = anomaly.get("agent_name", "unknown")
        metric = anomaly.get("metric", "unknown")
        detail = anomaly.get("detail", "")
        target = bugbanisher_id or anomaly.get("agent_id", "")
        if not target:
            continue
        message = (
            f"Anomaly detected: {agent_name}'s {metric} is abnormal.\n"
            f"Detail: {detail}\n\n"
            f"Investigate this anomaly. Check recent dispatch logs for {agent_name}, "
            f"look for patterns in failures or unusual behavior. "
            f"Report findings and suggest remediation if needed."
        )
        _self_dispatch(target, message, reason=f"Anomaly: {agent_name} {metric}",
                       priority="high")


def _self_dispatch_on_health_failure(failed_checks: list):
    """React to self-check failures by dispatching diagnostic tasks."""
    if not _self_dispatch_allowed():
        return
    target_id = None
    try:
        personas = _persona_list()
        for p in personas:
            name = (p.get("name", "") or "").lower()
            if name in ("vision", "logiclord", "logic lord"):
                target_id = p["id"]
                break
    except Exception:
        pass
    if not target_id:
        return
    checks_str = ", ".join(c[:50] for c in failed_checks[:3])
    message = (
        f"Porter self-check detected failures: {checks_str}\n\n"
        f"Diagnose the issue and suggest fixes. "
        f"Check service status, recent logs, and any recent code changes."
    )
    _self_dispatch(target_id, message, reason=f"Health failure: {checks_str}",
                   priority="high")


# ── Error Self-Heal (v0.28.22) ─────────────────────────────────────────

def _error_self_heal_once():
    """Scan recent logs for recurring errors and attempt auto-remediation."""
    import time as _sht
    prefs = _config.get("preferences", {})
    if not prefs.get("self_heal_enabled", False):
        return {"ok": True, "skipped": True, "reason": "disabled"}

    max_actions = prefs.get("self_heal_max_actions", 3)
    actions_taken = []

    try:
        conn = _db_conn()
        # Query mission log for recent errors (last hour)
        cutoff = _sht.time() - 3600
        errors = conn.execute(
            "SELECT category, event_type, message, COUNT(*) as cnt "
            "FROM mission_log WHERE level='error' AND ts >= ? "
            "GROUP BY category, event_type ORDER BY cnt DESC LIMIT 10",
            (cutoff,)
        ).fetchall()

        for err in errors:
            if len(actions_taken) >= max_actions:
                break
            cat = err["category"]
            etype = err["event_type"]
            cnt = err["cnt"]
            msg = err["message"]

            # v0.30.34 — Enhanced auto-triage with actionable remediation
            msg_lower = msg.lower()

            # 1. Heartbeat failures → disable to stop noise
            if "heartbeat" in cat and cnt >= 3:
                actions_taken.append(f"Paused heartbeat workflow (failed {cnt}x)")
                with _wf_lock:
                    if "heartbeat" in _wf_registry:
                        _wf_registry["heartbeat"]["enabled"] = False

            # 2. Rate limits → mark backend rate-limited with cooldown
            elif "rate" in msg_lower and ("limit" in msg_lower or "429" in msg_lower) and cnt >= 2:
                # Extract backend name from message
                for _bk in ["openclaw", "claude", "gemini", "codex", "ollama"]:
                    if _bk in msg_lower:
                        _backend_set_rate_limited(_bk, cooldown_seconds=300)
                        actions_taken.append(f"Set {_bk} rate-limited (5min cooldown, {cnt}x rate limit errors)")
                        break
                else:
                    actions_taken.append(f"Rate limit detected ({cnt}x): {msg[:80]}")

            # 3. OpenClaw gateway down → attempt restart
            elif "openclaw" in msg_lower and ("unresponsive" in msg_lower or "gateway" in msg_lower or "connection" in msg_lower) and cnt >= 3:
                try:
                    restart = _openclaw_restart()
                    if restart.get("ok"):
                        actions_taken.append(f"Restarted OpenClaw gateway (was down {cnt}x)")
                    else:
                        actions_taken.append(f"OpenClaw restart failed: {restart.get('error', '?')[:60]}")
                except Exception:
                    actions_taken.append(f"OpenClaw gateway down ({cnt}x), restart failed")

            # 4. Dispatch timeouts → increase timeout or log pattern
            elif "dispatch" in etype and "timeout" in msg_lower and cnt >= 5:
                actions_taken.append(f"Dispatch timeout pattern ({cnt}x): {msg[:80]} — consider increasing timeout")
                _emit_event("self_heal:timeout_pattern", {"count": cnt, "message": msg[:200]})

            # 5. DB lock/busy errors → reduce concurrent DB access
            elif ("database" in msg_lower or "locked" in msg_lower or "busy" in msg_lower) and cnt >= 3:
                actions_taken.append(f"Database contention ({cnt}x): {msg[:80]} — may need connection pooling")

            # 6. Backend probe failures → log with specific backend
            elif "probe" in etype and cnt >= 3:
                actions_taken.append(f"Backend probe failing ({cnt}x): {msg[:80]}")

            # 7. Memory/extraction errors → pause extraction temporarily
            elif ("extraction" in msg_lower or "cortex" in msg_lower) and cnt >= 5:
                actions_taken.append(f"Cortex extraction errors ({cnt}x): {msg[:80]}")

            # 8. Frontend JS errors → log pattern (client-side, can't auto-fix)
            elif "frontend" in cat and cnt >= 10:
                actions_taken.append(f"Client JS error storm ({cnt}x) [{etype}]: {msg[:60]}")

            # 9. Auth failures → possible brute force
            elif "auth" in cat and cnt >= 10:
                actions_taken.append(f"Auth failure spike ({cnt}x) — possible brute force: {msg[:60]}")

            # 10. Generic high-frequency → log for review
            elif cnt >= 10:
                actions_taken.append(f"High-frequency error ({cnt}x) [{cat}.{etype}]: {msg[:60]}")

        if actions_taken:
            log.info("Self-heal took %d actions: %s", len(actions_taken), "; ".join(actions_taken))
            mlog.emit("info", "self-heal", "self_heal.actions",
                      f"Took {len(actions_taken)} actions: {'; '.join(actions_taken)}")

        _wf_record_run("error_self_heal", success=True,
                       result=f"{len(actions_taken)} actions" if actions_taken else "clean")
        return {"ok": True, "actions": actions_taken}

    except Exception as e:
        log.warning("Self-heal error: %s", e)
        _wf_record_run("error_self_heal", success=False, error=str(e))
        return {"ok": False, "error": str(e)}



# ── Config Drift Detection (v0.30.36) ────────────────────────────────────

_last_config_hash = ""

def _config_drift_check():
    """v0.30.36 — Compare in-memory config against disk config. Log discrepancies."""
    global _last_config_hash
    import hashlib
    try:
        if not CONFIG_PATH.exists():
            return
        disk_raw = CONFIG_PATH.read_text(encoding="utf-8")
        disk_hash = hashlib.md5(disk_raw.encode()).hexdigest()
        # On first run, just record the hash
        if not _last_config_hash:
            _last_config_hash = disk_hash
            return
        # Check if disk config changed since last check (external edit)
        if disk_hash != _last_config_hash:
            _last_config_hash = disk_hash
            # Disk changed — compare keys with in-memory
            try:
                disk_cfg = json.loads(disk_raw)
            except Exception:
                mlog.emit("warning", "system", "config_drift.parse_error",
                    "porter_config.json on disk has invalid JSON — cannot compare")
                return
            mem_keys = set(_config.keys())
            disk_keys = set(disk_cfg.keys())
            added_on_disk = disk_keys - mem_keys
            removed_on_disk = mem_keys - disk_keys
            changed_values = []
            for k in mem_keys & disk_keys:
                if _config[k] != disk_cfg.get(k):
                    # Skip volatile keys that change at runtime
                    if k in ("schedules",):
                        continue
                    changed_values.append(k)
            if added_on_disk or removed_on_disk or changed_values:
                drift_summary = []
                if added_on_disk:
                    drift_summary.append(f"new keys on disk: {sorted(added_on_disk)}")
                if removed_on_disk:
                    drift_summary.append(f"keys missing from disk: {sorted(removed_on_disk)}")
                if changed_values:
                    drift_summary.append(f"changed values: {sorted(changed_values)}")
                detail = "; ".join(drift_summary)
                mlog.emit("warning", "system", "config_drift.detected",
                    f"Config drift detected — {detail}. Consider /api/reload to sync.")
                log.warning("Config drift: %s", detail)
                _emit_event("system:config_drift", {"drift": drift_summary})
            else:
                log.debug("Config file changed on disk but no meaningful drift (content equivalent)")
    except Exception as e:
        log.debug("Config drift check error: %s", e)


def _error_self_heal_loop():
    """Background daemon for error self-healing."""
    import time as _shlt
    _shlt.sleep(120)  # wait 2min after startup
    while True:
        if _wf_is_enabled("skill_mining"):
            _run_if_due("skill_mining", _skill_mining_run)
        # v0.29.27 — Session lifecycle sweep (lightweight, runs every cycle)
        try: _session_lifecycle_sweep()
        except Exception: pass
        if _wf_is_enabled("error_self_heal"):
            cfg = _config.get("preferences", {})
            if cfg.get("self_heal_enabled", False):
                _error_self_heal_once()
        # v0.30.36 — Config drift detection
        try: _config_drift_check()
        except Exception: pass
        # v0.30.41 — Pattern mining (every 6 hours)
        try:
            if not hasattr(_pattern_mining_run, '_last_run') or (_shlt.time() - _pattern_mining_run._last_run) > 21600:
                _pattern_mining_run()
                _pattern_mining_run._last_run = _shlt.time()
        except Exception: pass
        _shlt.sleep(3600)  # check hourly


# ── Agent Backend Eval (v0.28.19) ──────────────────────────────────────

_eval_agent_idx = 0

def _agent_eval_prompt(persona):
    name = persona.get("name", "Agent")
    role = persona.get("role", "general assistant")
    return f"Respond in 2 sentences as {name}. What is your primary role and how do you approach problems? (Role: {role})"

def _agent_eval_score(response, persona, latency_s):
    score = 0
    if latency_s < 3: score += 30
    elif latency_s < 8: score += 20
    elif latency_s < 15: score += 10
    rlen = len(response) if response else 0
    if 50 <= rlen <= 500: score += 20
    elif rlen > 0: score += max(0, 20 - abs(rlen - 275) // 25)
    name = persona.get("name", "").lower()
    role = persona.get("role", "").lower()
    rl = response.lower() if response else ""
    if name and name in rl: score += 15
    if role:
        role_words = [w for w in role.split() if len(w) > 3]
        matches = sum(1 for w in role_words if w in rl)
        score += min(15, matches * 5)
    if response and not response.startswith("Error") and 20 < rlen < 2000:
        score += 20
    elif response and rlen > 0:
        score += 10
    return min(100, score)

def _agent_eval_once():
    global _eval_agent_idx
    import time as _et
    try:
        conn = _db_conn()
        personas = conn.execute("SELECT id, name, role, avatar, preferred_backend FROM personas ORDER BY sort_order, name").fetchall()
        if not personas:
            return {"ok": False, "error": "No agents"}
        cols = [d[0] for d in conn.description]
        idx = _eval_agent_idx % len(personas)
        _eval_agent_idx = idx + 1
        p = dict(zip(cols, personas[idx]))
        results = []
        prompt = _agent_eval_prompt(p)
        for bk in PROVIDER_REGISTRY:
            if not _probe_provider(bk):
                continue
            t0 = _et.time()
            try:
                resp = dispatch_agent(prompt, bk, timeout=30)
                lat = _et.time() - t0
                rtxt = resp if isinstance(resp, str) else str(resp)
            except Exception as e:
                lat = _et.time() - t0
                rtxt = f"Error: {e}"
            sc = _agent_eval_score(rtxt, p, lat)
            ms = int(lat * 1000)
            passed = 1 if sc >= 40 else 0
            conn.execute(
                "INSERT INTO agent_eval_results (persona_id,backend,score,latency_ms,response_len,passed,created_at) VALUES (?,?,?,?,?,?,?)",
                (p["id"], bk, sc, ms, len(rtxt or ""), passed, _et.time()))
            results.append({"backend": bk, "score": sc, "latency_ms": ms, "passed": bool(passed)})
        conn.commit()
        best = max(results, key=lambda r: r["score"]) if results else {}
        log.info("Agent eval: %s — best=%s (score=%d)", p["name"], best.get("backend","?"), best.get("score",0))
        _wf_record_run("agent_backend_eval", success=True, result=f"{p['name']}: best={best.get('backend','?')} score={best.get('score',0)}")
        return {"ok": True, "persona": p["name"], "results": results, "best_score": best.get("score", 0)}
    except Exception as e:
        log.warning("Agent eval error: %s", e)
        _wf_record_run("agent_backend_eval", success=False, error=str(e))
        return {"ok": False, "error": str(e)}

def _agent_eval_loop():
    import time as _ael
    _ael.sleep(300)
    while True:
        try:
            cfg = _config
            if not cfg.get("agent_eval_enabled", False):
                _ael.sleep(3600)
                continue
            interval_h = cfg.get("agent_eval_interval_hours", 168)
            _agent_eval_once()
            _ael.sleep(max(600, interval_h * 3600 / max(1, len(PROVIDER_REGISTRY))))
        except Exception as e:
            log.warning("Agent eval loop error: %s", e)
            _ael.sleep(3600)


def _ai_rewrite_field(text, field_type="description", project_name=""):
    """Rewrite user-provided text into professional project copy. Non-blocking fallback to original."""
    if not text or len(text.strip()) < 15:
        return text.strip()
    prompt = (
        f"Rewrite this project {field_type} to be clear, concise, and professional. "
        f"Keep the same meaning and all facts. Return ONLY the rewritten text — no preamble, no quotes, no markdown.\n\n"
        f"Project: {project_name}\n"
        f"Original {field_type}: {text}"
    )
    try:
        result = dispatch_agent(prompt, "openclaw", timeout=15)
        if result.get("ok") and result.get("response", "").strip():
            rewritten = result["response"].strip()
            # Basic sanity: should not be drastically longer or contain meta-text
            if len(rewritten) < len(text) * 3 and not rewritten.lower().startswith("here"):
                log.debug("AI rewrite (%s): %r -> %r", field_type, text[:60], rewritten[:60])
                return rewritten
    except Exception as e:
        log.debug("AI rewrite failed for %s: %s", field_type, e)
    return text.strip()


def dispatch_agent(message, backend, model=None, timeout=120, run_id=None, chain_id=None, step_num=0):
    """Route a message to the specified backend and return normalized response."""
    import time as _dt
    import uuid as _uuid
    _dt_start = _dt.time()
    if not run_id:
        run_id = _uuid.uuid4().hex[:12]
    # Resolve active model if none specified
    requested_model = model
    if model is None:
        model = _get_active_model(backend) or None
    _sched_lane_key = ""
    _sched_wait_ms = 0
    fn = PROVIDER_REGISTRY.get(backend, {}).get('dispatch')
    if not fn:
        return {"ok": False, "error": f"Unknown backend: {backend}. Available: {', '.join(PROVIDER_REGISTRY.keys())}", "run_id": run_id}
    # Check if backend is in cooldown
    if not _backend_is_available(backend):
        _cd = _backend_health.get(backend, {})
        _cd_remaining = max(0, int(_cd.get("cooldown_until", 0) - _dt.time()))
        return {"ok": False, "error": f"{backend} rate-limited, cooldown {_cd_remaining}s remaining", "run_id": run_id}
    # Bridge context logged, not injected into prompt (avoids contaminating model output)
    log.info("Bridge dispatch: %s → %s (%s)", "porter", backend, message[:60])
    # Record outgoing message
    _record_agent_message(run_id, "porter", backend, message, status="in_progress", chain_id=chain_id, step_num=step_num)
    _emit_event("bridge:dispatch", {"run_id": run_id, "backend": backend, "prompt": message[:200]})
    mlog.emit("info", "bridge", "bridge.dispatch", f"Dispatch to {backend}", run_id=run_id, backend=backend, trace_id=_get_trace_id())
    try:
        _sched = _bridge_scheduler_acquire(backend, model or "", run_id=run_id, timeout_s=timeout)
        _sched_lane_key = str(_sched.get("lane_key") or "")
        _sched_wait_ms = int(_sched.get("wait_ms") or 0)
    except Exception as e:
        _update_agent_message(run_id, error=str(e)[:500], status="failed", duration_ms=0)
        _emit_event("bridge:error", {"run_id": run_id, "backend": backend, "error": str(e)[:200]})
        _record_bridge_benchmark(
            "dispatch",
            backend,
            requested_model=str(requested_model or model or ""),
            resolved_model=str(model or ""),
            ok=False,
            latency_ms=0,
            error=str(e),
            metadata={"run_id": run_id, "wait_ms": 0, "lane_key": "", "bridge": _bridge_runtime_semantics(backend, model or "")},
        )
        return {"ok": False, "error": str(e)[:500], "run_id": run_id}
    # v0.30.26 — Rate-limit auto-retry with exponential backoff
    _rl_max_retries = 3
    _rl_base_delay = 30  # seconds: 30, 60, 120
    _result = None
    try:
        for _rl_attempt in range(_rl_max_retries + 1):
            _dt_start = _dt.time()  # Reset timer per attempt
            _result = fn(message, model=model, timeout=timeout)
            _ok_check = bool(_result.get("ok", True))
            _err_check = str(_result.get("error", "") or "").lower()
            _rl_phrases = ["rate limit", "429", "quota exceeded", "too many requests", "overloaded", "capacity"]
            _is_rate_limit = any(p in _err_check for p in _rl_phrases)
            if _ok_check:
                _backend_set_ok(backend)
                break
            if not _is_rate_limit or _rl_attempt >= _rl_max_retries:
                if _is_rate_limit:
                    _backend_set_rate_limited(backend, 120 * (2 ** min(_rl_attempt, 3)))
                break
            _rl_delay = _rl_base_delay * (2 ** _rl_attempt)
            log.warning("Rate limit on %s (attempt %d/%d), retrying in %ds", backend, _rl_attempt + 1, _rl_max_retries, _rl_delay)
            mlog.emit("warn", "bridge", "dispatch.rate_limited",
                f"{backend} rate limited, retry {_rl_attempt+1}/{_rl_max_retries} in {_rl_delay}s",
                backend=backend, run_id=run_id or "")
            _emit_event("dispatch:rate_limited", {"backend": backend, "attempt": _rl_attempt + 1, "delay": _rl_delay, "run_id": run_id or ""})
            _dt.sleep(_rl_delay)
        dur_ms = int((_dt.time() - _dt_start) * 1000)
        _ok = bool(_result.get("ok", True))
        _err = str(_result.get("error", "") or "")
        _resolved_model = str(_result.get("model") or model or "")
        _record_backend_dispatch_result(backend, _ok, _err)
        _record_bridge_benchmark(
            "dispatch",
            backend,
            requested_model=str(requested_model or model or ""),
            resolved_model=_resolved_model,
            ok=_ok,
            latency_ms=dur_ms,
            error=_err,
            metadata={
                "run_id": run_id,
                "wait_ms": _sched_wait_ms,
                "lane_key": _sched_lane_key,
                "bridge": _result.get("bridge", _bridge_runtime_semantics(backend, _resolved_model)),
            },
        )
        _log_delegation(backend, message, _result, dur_ms)
        # Record response
        _update_agent_message(run_id, response=_result.get("text", "")[:5000],
                              status="complete" if _ok else "failed", model=_resolved_model,
                              tokens=_result.get("tokens", {}).get("total", 0), duration_ms=dur_ms)
        if not _ok and _err:
            _update_agent_message(run_id, error=_err[:500], status="failed", duration_ms=dur_ms)
            _emit_event("bridge:error", {"run_id": run_id, "backend": backend, "error": _err[:200]})
            mlog.emit("warn", "bridge", "bridge.fail", f"Bridge {backend} returned failure: {_err[:100]}", run_id=run_id, backend=backend, duration_ms=dur_ms, status="error", trace_id=_get_trace_id())
        else:
            _emit_event("bridge:response", {"run_id": run_id, "backend": backend, "ok": True, "duration_ms": dur_ms})
            mlog.emit("info", "bridge", "bridge.complete", f"Bridge {backend} OK ({dur_ms}ms)", run_id=run_id, backend=backend, duration_ms=dur_ms, status="ok", trace_id=_get_trace_id())
        _result["run_id"] = run_id
        return _result
    except Exception as e:
        dur_ms = int((_dt.time() - _dt_start) * 1000)
        log.error("Agent bridge [%s] exception: %s", backend, e)
        _record_backend_dispatch_result(backend, False, str(e))
        _record_bridge_benchmark(
            "dispatch",
            backend,
            requested_model=str(requested_model or model or ""),
            resolved_model=str(model or ""),
            ok=False,
            latency_ms=dur_ms,
            error=str(e),
            metadata={
                "run_id": run_id,
                "wait_ms": _sched_wait_ms,
                "lane_key": _sched_lane_key,
                "bridge": _bridge_runtime_semantics(backend, model or ""),
            },
        )
        _update_agent_message(run_id, error=str(e)[:500], status="failed", duration_ms=dur_ms)
        _emit_event("bridge:error", {"run_id": run_id, "backend": backend, "error": str(e)[:200]})
        mlog.emit("error", "bridge", "bridge.fail", f"Bridge {backend} failed: {str(e)[:100]}", run_id=run_id, backend=backend, duration_ms=dur_ms, status="error", trace_id=_get_trace_id())
        return {"ok": False, "error": str(e)[:500], "run_id": run_id}
    finally:
        if _sched_lane_key:
            _bridge_scheduler_release(backend, _sched_lane_key)


def _record_agent_message(run_id, from_agent, to_agent, message, status="pending", chain_id=None, step_num=0):
    """Insert an agent message into the database."""
    try:
        conn = _db_conn()
        conn.execute("""INSERT INTO agent_messages (run_id, from_agent, to_agent, message, status, chain_id, step_num)
                        VALUES (?, ?, ?, ?, ?, ?, ?)""",
                     (run_id, from_agent, to_agent, message[:10000], status, chain_id, step_num))
        conn.commit()
        conn.close()
    except Exception as e:
        log.debug("Failed to record agent message: %s", e)

def _update_agent_message(run_id, response=None, status=None, model=None, tokens=0, duration_ms=0, error=None):
    """Update an agent message with its response."""
    try:
        conn = _db_conn()
        sets = []
        vals = []
        if response is not None:
            sets.append("response=?"); vals.append(response)
        if status:
            sets.append("status=?"); vals.append(status)
        if model:
            sets.append("model=?"); vals.append(model)
        if tokens:
            sets.append("tokens_total=?"); vals.append(tokens)
        if duration_ms:
            sets.append("duration_ms=?"); vals.append(duration_ms)
        if error:
            sets.append("error=?"); vals.append(error)
        if status in ("complete", "failed"):
            sets.append("completed_at=strftime('%s','now')")
        if sets:
            vals.append(run_id)
            conn.execute(f"UPDATE agent_messages SET {', '.join(sets)} WHERE run_id=?", vals)
            conn.commit()
        conn.close()
    except Exception as e:
        log.debug("Failed to update agent message: %s", e)


def _run_chain(chain_id, steps, initial_input, timeout_per_step=120):
    """Run a multi-step chain: probe → dispatch → pipe output forward.
    Emits SSE events: chain:start, chain:step, chain:complete, chain:error.
    """
    import time as _ct
    import uuid as _cu
    # v0.28.4 — Loop guard: check before starting chain
    _lg_ok, _lg_msg = _loop_guard_check(chain_id, sender_is_human=False)
    if not _lg_ok:
        _emit_event("chain:error", {"chain_id": chain_id, "error": _lg_msg})
        return {"chain_id": chain_id, "status": "blocked", "error": _lg_msg, "loop_guard": True}
    _emit_event("chain:start", {"chain_id": chain_id, "steps": len(steps), "input": initial_input[:200]})
    mlog.emit("info", "chain", "chain.start", f"Chain {chain_id} started ({len(steps)} steps)",
              chain_id=chain_id, step_count=len(steps), trace_id=_get_trace_id())

    previous = initial_input
    results = []
    for idx, step in enumerate(steps):
        step_backend = step.get("backend", "openclaw")
        prompt_template = step.get("prompt", "{input}")
        step_model = step.get("model")
        step_timeout = step.get("timeout", timeout_per_step)

        # Substitute placeholders
        prompt = prompt_template.replace("{input}", initial_input).replace("{previous}", previous)

        _emit_event("chain:step", {"chain_id": chain_id, "step": idx, "backend": step_backend,
                                    "prompt": prompt[:200], "status": "started"})
        mlog.emit("info", "chain", "chain.step.start",
                  f"Chain {chain_id} step {idx}: {step_backend}",
                  chain_id=chain_id, step_num=idx, backend=step_backend, trace_id=_get_trace_id())

        # Dispatch — persona or direct backend
        run_id = f"{chain_id}-s{idx}"
        step_persona_id = step.get("persona_id")
        if step_persona_id:
            # Route through persona layer (handles backend resolution + SOUL injection)
            result = dispatch_to_persona(prompt, step_persona_id, timeout=step_timeout,
                                         run_id=run_id, chain_id=chain_id, step_num=idx)
        else:
            # Direct backend dispatch (original behavior)
            if not _probe_provider(step_backend):
                error_msg = f"Backend {step_backend} unavailable at step {idx}"
                _emit_event("chain:error", {"chain_id": chain_id, "step": idx, "error": error_msg})
                mlog.emit("error", "chain", "chain.step.fail", error_msg,
                          chain_id=chain_id, step_num=idx, backend=step_backend, trace_id=_get_trace_id())
                results.append({"step": idx, "backend": step_backend, "ok": False, "error": error_msg})
                break
            result = dispatch_agent(prompt, step_backend, model=step_model, timeout=step_timeout,
                                    run_id=run_id, chain_id=chain_id, step_num=idx)

        if result.get("ok"):
            previous = result.get("text", "")
            results.append({"step": idx, "backend": step_backend, "ok": True,
                            "text": previous[:500], "run_id": run_id,
                            "duration_ms": result.get("duration_ms", 0),
                            "tokens": result.get("tokens", {})})
            _emit_event("chain:step", {"chain_id": chain_id, "step": idx, "backend": step_backend,
                                        "status": "complete", "duration_ms": result.get("duration_ms", 0)})
            mlog.emit("info", "chain", "chain.step.complete",
                      f"Chain {chain_id} step {idx} OK ({result.get('duration_ms', 0)}ms)",
                      chain_id=chain_id, step_num=idx, backend=step_backend,
                      duration_ms=result.get("duration_ms", 0), trace_id=_get_trace_id())
        else:
            error = result.get("error", "unknown")
            results.append({"step": idx, "backend": step_backend, "ok": False,
                            "error": error[:500], "run_id": run_id})
            _emit_event("chain:error", {"chain_id": chain_id, "step": idx,
                                         "error": error[:200], "backend": step_backend})
            mlog.emit("error", "chain", "chain.step.fail",
                      f"Chain {chain_id} step {idx} failed: {error[:100]}",
                      chain_id=chain_id, step_num=idx, backend=step_backend, trace_id=_get_trace_id())
            break  # Stop on first failure

    # Chain complete
    all_ok = all(r.get("ok") for r in results) and len(results) == len(steps)
    total_dur = sum(r.get("duration_ms", 0) for r in results)
    status = "complete" if all_ok else "failed"
    _emit_event("chain:complete", {"chain_id": chain_id, "status": status,
                                    "steps_completed": len(results), "total_steps": len(steps),
                                    "total_duration_ms": total_dur,
                                    "final_output": previous[:500] if all_ok else ""})
    mlog.emit("info" if all_ok else "error", "chain", f"chain.{status}",
              f"Chain {chain_id} {status} ({len(results)}/{len(steps)} steps, {total_dur}ms)",
              chain_id=chain_id, status=status, steps_completed=len(results),
              total_steps=len(steps), duration_ms=total_dur, trace_id=_get_trace_id())
    return {"chain_id": chain_id, "status": status, "results": results,
            "final_output": previous if all_ok else "", "total_duration_ms": total_dur}


def _run_build_workflow(build_id, task_desc, backend=None, auto_commit=False, auto_restart=False):
    """Run an autonomous build workflow: dispatch task to an agent and handle results."""
    import time as _bt
    log.info("Build %s started: %s", build_id, task_desc[:100])
    _emit_event("build:start", {"build_id": build_id, "task": task_desc[:200]})

    # Pick backend
    if not backend:
        backend, _ = _smart_route(task_desc)

    # Step 1: Dispatch the task
    result = dispatch_agent(task_desc, backend, run_id=build_id, timeout=180)

    if not result.get("ok"):
        log.warning("Build %s failed: %s", build_id, result.get("error", "unknown"))
        _emit_event("build:failed", {"build_id": build_id, "error": result.get("error", "")[:200]})
        return

    response_text = result.get("text", "")
    log.info("Build %s got response (%d chars)", build_id, len(response_text))

    # Step 2: Auto-commit if requested
    if auto_commit:
        try:
            import subprocess
            porter_dir = str(Path(__file__).parent)
            subprocess.run(["git", "add", "-A"], cwd=porter_dir, capture_output=True, timeout=10)
            commit_msg = f"Auto-build {build_id}: {task_desc[:60]}"
            subprocess.run(["git", "commit", "-m", commit_msg], cwd=porter_dir, capture_output=True, timeout=10)
            subprocess.run(["git", "push"], cwd=porter_dir, capture_output=True, timeout=30)
            log.info("Build %s: auto-committed and pushed", build_id)
            _emit_event("build:committed", {"build_id": build_id})
        except Exception as e:
            log.warning("Build %s: auto-commit failed: %s", build_id, e)

    # Step 3: Auto-restart if requested
    if auto_restart:
        try:
            import subprocess
            subprocess.run(["systemctl", "--user", "restart", "porter"], capture_output=True, timeout=10)
            log.info("Build %s: auto-restarted porter", build_id)
            _emit_event("build:restarted", {"build_id": build_id})
        except Exception as e:
            log.warning("Build %s: auto-restart failed: %s", build_id, e)

    _emit_event("build:complete", {"build_id": build_id, "backend": backend,
                                    "tokens": result.get("tokens", {}).get("total", 0)})


def _coord_log_path() -> Path:
    return RUNTIME_DIR / "coordination.jsonl"


def _append_coordination_event(event: dict) -> None:
    """Append a coordination event to runtime log (best effort)."""
    try:
        p = _coord_log_path()
        p.parent.mkdir(parents=True, exist_ok=True)
        with p.open("a", encoding="utf-8") as f:
            f.write(json.dumps(event, ensure_ascii=True) + "\n")
    except Exception as e:
        log.debug("Coordination log append failed: %s", e)



# ── Coordination Ledger — shared work board for model deconfliction ──

def _ledger_claim(model: str, scope: str, message: str = "", ttl_minutes: int = 30, version_at: str = "", project_id: str = "", task_id: str = "") -> dict:
    model = str(model or "").strip().lower()
    scope = str(scope or "").strip()
    if not model or not scope:
        return {"ok": False, "error": "model and scope required"}
    now = time.time()
    conn = _db_conn()
    existing = conn.execute(
        "SELECT id, model, message, expires_at FROM coordination_ledger "
        "WHERE scope=? AND entry_type='claim' AND resolved=0 AND expires_at>? LIMIT 1",
        (scope, now)
    ).fetchone()
    if existing and existing["model"] != model:
        conn.close()
        return {"ok": False, "conflict": True, "claimed_by": existing["model"],
                "message": existing["message"], "expires_at": existing["expires_at"]}
    conn.execute(
        "UPDATE coordination_ledger SET resolved=1 WHERE scope=? AND model=? AND entry_type='claim' AND resolved=0",
        (scope, model)
    )
    entry_id = f"cl-{int(now)}-{uuid.uuid4().hex[:8]}"
    expires_at = now + (ttl_minutes * 60)
    conn.execute(
        "INSERT INTO coordination_ledger (id, ts, model, entry_type, scope, message, project_id, task_id, version_at, ttl_minutes, expires_at) "
        "VALUES (?, ?, ?, 'claim', ?, ?, ?, ?, ?, ?, ?)",
        (entry_id, now, model, scope, str(message or ""), str(project_id or ""), str(task_id or ""), str(version_at or ""), ttl_minutes, expires_at)
    )
    conn.commit()
    conn.close()
    _emit_event("coordination:claim", {"model": model, "scope": scope, "message": message,
                                       "project_id": project_id, "task_id": task_id})
    return {"ok": True, "id": entry_id, "scope": scope, "expires_at": expires_at}


def _ledger_update(model: str, scope: str, entry_type: str, message: str = "", version_at: str = "", context: str = "", project_id: str = "", task_id: str = "") -> dict:
    model = str(model or "").strip().lower()
    scope = str(scope or "").strip()
    entry_type = str(entry_type or "").strip().lower()
    if entry_type not in ("progress", "complete", "handoff", "block", "release"):
        return {"ok": False, "error": "entry_type must be progress|complete|handoff|block|release"}
    now = time.time()
    conn = _db_conn()
    entry_id = f"cl-{int(now)}-{uuid.uuid4().hex[:8]}"
    conn.execute(
        "INSERT INTO coordination_ledger (id, ts, model, entry_type, scope, message, project_id, task_id, version_at, context) "
        "VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)",
        (entry_id, now, model, entry_type, scope, str(message or "")[:500],
         str(project_id or ""), str(task_id or ""), str(version_at or ""), str(context or "")[:2000])
    )
    if entry_type in ("complete", "release"):
        conn.execute(
            "UPDATE coordination_ledger SET resolved=1 WHERE scope=? AND model=? AND entry_type='claim' AND resolved=0",
            (scope, model)
        )
    conn.commit()
    conn.close()
    _emit_event("coordination:" + entry_type, {"model": model, "scope": scope, "message": message,
                                               "project_id": project_id, "task_id": task_id})
    return {"ok": True, "id": entry_id}


def _ledger_active() -> list:
    now = time.time()
    try:
        conn = _db_conn()
        conn.execute("UPDATE coordination_ledger SET resolved=1 WHERE entry_type='claim' AND resolved=0 AND expires_at<? AND expires_at>0", (now,))
        conn.commit()
        rows = conn.execute(
            "SELECT id, ts, model, entry_type, scope, message, version_at, ttl_minutes, expires_at "
            "FROM coordination_ledger WHERE entry_type='claim' AND resolved=0 AND expires_at>? "
            "ORDER BY ts DESC", (now,)
        ).fetchall()
        conn.close()
        return [dict(r) for r in rows]
    except Exception:
        return []


def _ledger_recent(limit: int = 50) -> list:
    try:
        conn = _db_conn()
        rows = conn.execute(
            "SELECT id, ts, model, entry_type, scope, message, version_at, context, resolved "
            "FROM coordination_ledger ORDER BY ts DESC LIMIT ?",
            (max(1, min(200, limit)),)
        ).fetchall()
        conn.close()
        return [dict(r) for r in rows]
    except Exception:
        return []


def _ledger_conflicts() -> list:
    conflicts = []
    try:
        conn = _db_conn()
        now = time.time()
        vc = conn.execute(
            "SELECT version_at, GROUP_CONCAT(DISTINCT model) as models, COUNT(DISTINCT model) as cnt "
            "FROM coordination_ledger WHERE entry_type='complete' AND version_at != '' "
            "GROUP BY version_at HAVING cnt > 1"
        ).fetchall()
        for row in vc:
            conflicts.append({"type": "version_collision", "version": row["version_at"], "models": row["models"]})
        sc = conn.execute(
            "SELECT scope, GROUP_CONCAT(DISTINCT model) as models, COUNT(DISTINCT model) as cnt "
            "FROM coordination_ledger WHERE entry_type='claim' AND resolved=0 AND expires_at>? "
            "GROUP BY scope HAVING cnt > 1", (now,)
        ).fetchall()
        for row in sc:
            conflicts.append({"type": "scope_collision", "scope": row["scope"], "models": row["models"]})
        conn.close()
    except Exception:
        pass
    return conflicts




